-- Seed the full Yingoh NCLEX question bank into Supabase.
-- Inserts only prompts that do not already exist, so it is safe to rerun.

insert into public.questions (
  topic,
  question_type,
  prompt,
  choices,
  correct_answer,
  rationale,
  strategy,
  client_need,
  clinical_judgment,
  status
)
select *
from (values
  ('Pharmacology', 'mcq', 'A nurse is administering metformin to a patient with type 2 diabetes. Which laboratory finding should the nurse report to the provider immediately before giving this medication?', '[{"id":"a","text":"Blood glucose of 180 mg/dL"},{"id":"b","text":"Serum creatinine of 2.8 mg/dL"},{"id":"c","text":"HbA1c of 7.2%"},{"id":"d","text":"Blood pressure of 130/82 mmHg"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Metformin is contraindicated with significant renal impairment (creatinine >1.4 mg/dL in women, >1.5 in men) due to the risk of lactic acidosis. A creatinine of 2.8 mg/dL requires holding the medication and notifying the provider.', '', '', '', 'published'),
  ('Safety and Infection Control', 'sata', 'A nurse is caring for a patient with Clostridioides difficile (C. diff) colitis. Which actions are appropriate? (Select all that apply)', '[{"id":"a","text":"Wear gloves when entering the room"},{"id":"b","text":"Use alcohol-based hand rub after removing gloves"},{"id":"c","text":"Wear a gown when entering the room"},{"id":"d","text":"Wash hands with soap and water"},{"id":"e","text":"Place patient in a negative pressure room"},{"id":"f","text":"Wear an N95 respirator"}]'::jsonb, '{"ids":["a","c","d"]}'::jsonb, 'C. diff requires contact precautions: gown and gloves. Alcohol-based hand rubs do NOT kill C. diff spores — soap and water is required. Negative pressure rooms and N95s are for airborne precautions, not C. diff.', '', '', '', 'published'),
  ('Maternal and Newborn', 'mcq', 'A nurse calculates an APGAR score at 5 minutes. The newborn has HR 110/min, slow irregular respirations, some extremity flexion, grimace to stimulation, and acrocyanosis. What is the APGAR score?', '[{"id":"a","text":"4"},{"id":"b","text":"5"},{"id":"c","text":"6"},{"id":"d","text":"7"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'HR >100 = 2, Respiratory slow/irregular = 1, Muscle tone some flexion = 1, Reflex grimace = 1, Color acrocyanosis = 0. Total = 5. Scores 4–6 indicate moderate depression requiring stimulation.', '', '', '', 'published'),
  ('NGN Case Studies', 'sata', 'A nurse assesses a patient 12 hours post-abdominal surgery: T 38.9°C, HR 102, BP 118/76, SpO2 95%, urine output 20 mL over 2 hours. Which findings require immediate intervention? (Select all that apply)', '[{"id":"a","text":"Temperature 38.9°C"},{"id":"b","text":"Heart rate 102"},{"id":"c","text":"Urine output 20 mL over 2 hours"},{"id":"d","text":"SpO2 95%"},{"id":"e","text":"Respiratory rate 22"},{"id":"f","text":"Blood pressure 118/76"}]'::jsonb, '{"ids":["a","c"]}'::jsonb, 'Post-op day 0–1 fever (atelectasis) requires incentive spirometry and deep breathing. Urine output 20 mL/2 hr = 10 mL/hr — below the 30 mL/hr minimum, indicating oliguria. Other values are acceptable post-operatively.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A nurse is preparing to administer digoxin. Which finding should cause the nurse to withhold the medication and contact the provider?', '[{"id":"a","text":"Apical pulse of 56 beats per minute"},{"id":"b","text":"Blood pressure of 118/72 mmHg"},{"id":"c","text":"Serum potassium of 4.1 mEq/L"},{"id":"d","text":"Serum digoxin level of 0.8 ng/mL"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Withhold digoxin if apical pulse <60 bpm and notify the provider. Digoxin is a negative chronotrope; giving it with a rate of 56 could cause dangerous bradycardia or heart block.', '', '', '', 'published'),
  ('Medical-Surgical', 'sata', 'A nurse is caring for a patient with diabetic ketoacidosis (DKA). Which clinical findings are consistent with this diagnosis? (Select all that apply)', '[{"id":"a","text":"Kussmaul respirations"},{"id":"b","text":"Blood glucose 520 mg/dL"},{"id":"c","text":"Fruity breath odor"},{"id":"d","text":"Bradycardia"},{"id":"e","text":"Polyuria and polydipsia"},{"id":"f","text":"Diaphoresis and pallor"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'DKA: Kussmaul respirations (compensation for metabolic acidosis), hyperglycemia >250 mg/dL, fruity/acetone breath (ketones), polyuria and polydipsia. Bradycardia and diaphoresis/pallor are not DKA findings.', '', '', '', 'published'),
  ('Mental Health', 'mcq', 'A patient is prescribed lithium carbonate for bipolar disorder. Which serum level indicates toxicity requiring immediate intervention?', '[{"id":"a","text":"0.6 mEq/L"},{"id":"b","text":"0.9 mEq/L"},{"id":"c","text":"1.2 mEq/L"},{"id":"d","text":"2.1 mEq/L"}]'::jsonb, '{"ids":["d"]}'::jsonb, 'Therapeutic lithium range is 0.6–1.2 mEq/L. Levels >1.5 indicate toxicity; >2.0 is severe toxicity requiring emergency treatment including IV fluids and possible hemodialysis.', '', '', '', 'published'),
  ('Pediatrics', 'mcq', 'A nurse is assessing an 18-month-old child. Which developmental milestone should the nurse expect?', '[{"id":"a","text":"Speaking in 4–5 word sentences"},{"id":"b","text":"Walking up stairs with alternating feet"},{"id":"c","text":"Using a spoon and cup with some spilling"},{"id":"d","text":"Drawing a circle"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'At 18 months, toddlers use a spoon and cup with some spilling. Four-to-five word sentences, stair-climbing with alternating feet, and drawing circles are ~3-year milestones.', '', '', '', 'published'),
  ('Medical-Surgical', 'sata', 'A nurse teaches a patient prescribed warfarin. Which foods should be eaten in consistent amounts because they may decrease warfarin effectiveness? (Select all that apply)', '[{"id":"a","text":"Spinach"},{"id":"b","text":"Kale"},{"id":"c","text":"Grapefruit"},{"id":"d","text":"Broccoli"},{"id":"e","text":"Bananas"},{"id":"f","text":"Brussels sprouts"}]'::jsonb, '{"ids":["a","b","d","f"]}'::jsonb, 'Vitamin K antagonizes warfarin. High vitamin K foods include spinach, kale, broccoli, and Brussels sprouts. Patients should eat these consistently, not avoid them, to maintain stable INR.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A nurse is administering morphine sulfate IV post-operatively. Which equipment must be at the bedside before administering?', '[{"id":"a","text":"Blood pressure cuff and stethoscope"},{"id":"b","text":"Naloxone and resuscitation equipment"},{"id":"c","text":"Blood glucose monitor"},{"id":"d","text":"IV calcium gluconate"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Before administering opioids, naloxone (Narcan) and resuscitation equipment must be at bedside. Opioids can cause respiratory depression; naloxone is the required antidote.', '', '', '', 'published'),
  ('Safety and Infection Control', 'mcq', 'A nurse is preparing to administer blood. Which action is the priority to prevent a transfusion reaction?', '[{"id":"a","text":"Prime IV tubing with normal saline"},{"id":"b","text":"Verify the blood product with another nurse at the bedside"},{"id":"c","text":"Check vital signs 15 minutes after starting"},{"id":"d","text":"Obtain IV access with an 18-gauge catheter"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Two licensed nurses must verify blood type, unit number, expiration date, and patient ID at bedside before transfusion. This is the priority action to prevent hemolytic transfusion reactions.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient has a serum potassium of 2.8 mEq/L. Which assessment finding is most consistent with this result?', '[{"id":"a","text":"Muscle weakness and leg cramps"},{"id":"b","text":"Peaked T waves on ECG"},{"id":"c","text":"Bradycardia"},{"id":"d","text":"Paresthesias of the face"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Hypokalemia (<3.5 mEq/L) causes muscle weakness, cramps, and fatigue. Peaked T waves and bradycardia are hyperkalemia signs. Facial paresthesias are associated with hypocalcemia.', '', '', '', 'published'),
  ('NGN Case Studies', 'sata', 'A nurse reviews orders for a patient with acute heart failure. Which orders should be clarified before implementing? (Select all that apply)', '[{"id":"a","text":"0.9% NaCl 500 mL IV bolus over 1 hour"},{"id":"b","text":"Furosemide 40 mg IV push"},{"id":"c","text":"Restrict fluids to 1500 mL/day"},{"id":"d","text":"Morphine sulfate 2 mg IV PRN for air hunger"},{"id":"e","text":"High sodium diet"},{"id":"f","text":"Daily weights"}]'::jsonb, '{"ids":["a","e"]}'::jsonb, 'IV saline bolus worsens fluid overload and pulmonary edema in acute HF. A high sodium diet exacerbates fluid retention. Furosemide, fluid restriction, morphine for dyspnea, and daily weights are all appropriate HF interventions.', '', '', '', 'published'),
  ('Maternal and Newborn', 'sata', 'A nurse assesses a patient in active labor. Which findings require immediate intervention? (Select all that apply)', '[{"id":"a","text":"Fetal heart rate of 90 bpm for 3 minutes"},{"id":"b","text":"Contractions every 3–4 minutes lasting 50 seconds"},{"id":"c","text":"Late decelerations on the fetal monitor"},{"id":"d","text":"Maternal blood pressure of 158/106 mmHg"},{"id":"e","text":"Cervical dilation of 7 cm"},{"id":"f","text":"Clear amniotic fluid"}]'::jsonb, '{"ids":["a","c","d"]}'::jsonb, 'Fetal bradycardia <110 bpm for >3 min requires repositioning, O2, and provider notification. Late decelerations indicate uteroplacental insufficiency. BP 158/106 meets severe hypertension in pregnancy criteria — magnesium sulfate and provider notification required.', '', '', '', 'published'),
  ('Leadership and Management', 'mcq', 'A charge nurse is making shift assignments. Which patient should be assigned to the most experienced RN?', '[{"id":"a","text":"Patient with COPD requiring chest physiotherapy"},{"id":"b","text":"Patient with new colostomy requiring discharge teaching"},{"id":"c","text":"Patient with septic shock receiving vasopressors"},{"id":"d","text":"Patient with type 2 diabetes preparing for discharge"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Match patient acuity to nurse competency. Septic shock with vasopressors requires complex hemodynamic monitoring, medication titration, and critical thinking — the most demanding assignment.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A nurse assesses a patient 24 hours post-thyroidectomy. Which finding requires the most immediate action?', '[{"id":"a","text":"Serum calcium 7.2 mg/dL with positive Trousseau sign"},{"id":"b","text":"Hoarseness when speaking"},{"id":"c","text":"Incision pain rated 5/10"},{"id":"d","text":"Temperature of 37.8°C"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Post-thyroidectomy hypocalcemia from parathyroid damage can progress to tetany, laryngospasm, and seizures. Calcium 7.2 mg/dL with positive Trousseau sign requires immediate IV calcium gluconate.', '', '', '', 'published'),
  ('Mental Health', 'sata', 'A patient is admitted after a suicide attempt. Which nursing interventions are appropriate? (Select all that apply)', '[{"id":"a","text":"Remove all potentially harmful items from the environment"},{"id":"b","text":"Maintain 1:1 supervision at all times"},{"id":"c","text":"Ask the patient directly about suicidal ideation"},{"id":"d","text":"Avoid discussing the attempt to prevent distress"},{"id":"e","text":"Establish a therapeutic nurse–patient relationship"},{"id":"f","text":"Document the patient''s statements and behaviors"}]'::jsonb, '{"ids":["a","b","c","e","f"]}'::jsonb, 'Suicide precautions include environmental safety, 1:1 supervision, and direct assessment — asking directly does NOT increase risk. Therapeutic relationship and thorough documentation are essential. Avoiding discussion (D) is incorrect.', '', '', '', 'published'),
  ('Pharmacology', 'sata', 'A nurse is preparing to administer heparin subcutaneously. Which actions should the nurse take? (Select all that apply)', '[{"id":"a","text":"Verify the aPTT before administration"},{"id":"b","text":"Administer in the abdomen, rotating sites"},{"id":"c","text":"Massage the injection site after administration"},{"id":"d","text":"Have protamine sulfate available as an antidote"},{"id":"e","text":"Use a 1-inch 21-gauge needle"},{"id":"f","text":"Monitor platelet count for HIT"}]'::jsonb, '{"ids":["a","b","d","f"]}'::jsonb, 'Monitor aPTT; rotate abdominal sites; keep protamine sulfate available; monitor platelets for HIT (day 5–10). Do NOT massage (causes bruising). Use 5/8-inch, 25–27 gauge needle for subcutaneous injection.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with a bowel obstruction has an NG tube on low intermittent suction. Labs: Na 138, K 2.9, Cl 88, HCO3 32. Which acid-base imbalance is present?', '[{"id":"a","text":"Metabolic acidosis"},{"id":"b","text":"Metabolic alkalosis"},{"id":"c","text":"Respiratory acidosis"},{"id":"d","text":"Respiratory alkalosis"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'NG suction removes gastric HCl, causing loss of H+ and Cl−. Result: elevated HCO3 (32), low Cl (88), and hypokalemia (2.9). This is metabolic alkalosis.', '', '', '', 'published'),
  ('Leadership and Management', 'sata', 'A nurse is delegating tasks to unlicensed assistive personnel (UAP). Which tasks can be safely delegated? (Select all that apply)', '[{"id":"a","text":"Measuring and recording urinary output"},{"id":"b","text":"Assessing a patient who reports increased pain"},{"id":"c","text":"Obtaining vital signs on a stable patient"},{"id":"d","text":"Teaching a patient how to use an incentive spirometer"},{"id":"e","text":"Reporting urine output of 20 mL/hr to the nurse"},{"id":"f","text":"Ambulating a post-stroke patient independently"}]'::jsonb, '{"ids":["a","c","e"]}'::jsonb, 'UAPs can measure and record I&O, obtain vital signs on stable patients, and report objective measurements. Assessment, teaching, and ambulating post-stroke patients require nursing judgment and cannot be delegated.', '', '', '', 'published'),
  ('NGN Case Studies', 'bow_tie', 'A 68-year-old client is admitted to the ICU with a 3-day history of productive cough, fever of 39.2°C, and confusion. Oxygen saturation is 88% on room air. BP is 88/54 mmHg. The client''s family reports he lives alone and has type 2 diabetes and COPD. ABGs: pH 7.28, PaCO2 52, HCO3 22. WBC 22,000. Chest X-ray shows bilateral infiltrates.', '[]'::jsonb, '{"ids":[]}'::jsonb, 'This client meets criteria for septic shock secondary to pneumonia with concurrent respiratory acidosis and hypoxemia. Priority actions: administer supplemental oxygen and position HOB 30–45°, initiate broad-spectrum antibiotics within the first hour, and establish IV access for fluid resuscitation. Key parameters to monitor: oxygen saturation and ABGs (respiratory status), blood pressure and MAP (hemodynamic stability), and blood cultures (source identification). Avoid vasopressors before adequate fluid resuscitation.', '', '', '', 'published'),
  ('NGN Case Studies', 'matrix', 'A nurse is caring for a 54-year-old client admitted for acute decompensated heart failure. Vitals: BP 156/98, HR 108, RR 26, SpO₂ 90%, temp 37.1°C. The client has 3+ pitting edema in bilateral lower extremities, JVD, and audible crackles bilaterally. Orders include: IV furosemide 40 mg, continuous cardiac monitoring, daily weights, sodium restriction 2g/day, and supplemental oxygen. For each nursing intervention, indicate whether it is Indicated, Contraindicated, or Not Applicable.', '[]'::jsonb, '{"ids":[]}'::jsonb, 'In acute decompensated HF: IV furosemide reduces fluid overload (Indicated); positioning HOB 45° reduces preload and improves oxygenation (Indicated); daily weights monitor fluid status (Indicated). Encouraging oral fluid intake worsens fluid overload (Contraindicated). Sodium restriction is already ordered and would be managed by dietary team, not a direct nursing intervention in this context (Not Applicable as a nursing action; it is a dietary order). Ambulating in the acute decompensated phase with SpO₂ 90% is Contraindicated.', '', '', '', 'published'),
  ('NGN Case Studies', 'ordered_response', 'A nurse receives a shift report on a client who had an emergency appendectomy 6 hours ago. On assessment, the nurse notes sudden onset of tachycardia (HR 128), diaphoresis, abdominal rigidity, and temperature 38.9°C. The client states the pain has changed from 4/10 to 9/10 and feels "different." Place the following nursing actions in the correct order of priority (1 = first action, 5 = last action).', '[{"id":"a","text":"Notify the surgeon immediately of assessment findings"},{"id":"b","text":"Assess the client''s airway, breathing, and circulation"},{"id":"c","text":"Obtain vital signs and oxygen saturation"},{"id":"d","text":"Prepare the client for potential return to the OR"},{"id":"e","text":"Document all findings and interventions in the medical record"}]'::jsonb, '{"ids":[],"order":["b","c","a","d","e"]}'::jsonb, 'Use the nursing process and ABCs. First: assess ABCs (B) — immediate threat identification. Second: obtain full vital signs and SpO₂ to quantify deterioration (C). Third: notify the surgeon with complete SBAR — these findings suggest peritonitis from anastomotic leak (A). Fourth: prepare client for surgical intervention which may be imminent (D). Finally: document all findings and the chain of communication (E).', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A nurse is administering warfarin. Which laboratory value should be monitored to evaluate therapeutic effectiveness?', '[{"id":"a","text":"aPTT"},{"id":"b","text":"PT/INR"},{"id":"c","text":"Platelet count"},{"id":"d","text":"Bleeding time"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Warfarin (a vitamin K antagonist) effectiveness is monitored with PT/INR. Therapeutic INR for most indications is 2.0–3.0. aPTT monitors heparin therapy.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient is receiving IV vancomycin. The nurse notices flushing, erythema, and hypotension developing during the infusion. What is the priority action?', '[{"id":"a","text":"Administer diphenhydramine IV push"},{"id":"b","text":"Stop the infusion and notify the provider"},{"id":"c","text":"Slow the infusion rate and monitor"},{"id":"d","text":"Obtain a vancomycin trough level"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Red Man Syndrome is a rate-related reaction to vancomycin, not a true allergy. Slowing the infusion rate (over 60–90 min) resolves symptoms. It is not an IgE-mediated hypersensitivity reaction requiring stopping the drug.', '', '', '', 'published'),
  ('Pharmacology', 'sata', 'A nurse is teaching a patient newly prescribed atorvastatin. Which instructions should be included? (Select all that apply)', '[{"id":"a","text":"Report unexplained muscle pain or weakness"},{"id":"b","text":"Avoid grapefruit juice"},{"id":"c","text":"Take the medication in the morning for best effect"},{"id":"d","text":"Monitor LFTs periodically"},{"id":"e","text":"Expect a rash during the first week"}]'::jsonb, '{"ids":["a","b","d"]}'::jsonb, 'Statins can cause myopathy/rhabdomyolysis (report muscle pain). Grapefruit inhibits CYP3A4 increasing statin levels. Liver function should be monitored. Statins are given at any time of day (not only morning). A rash is not expected.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A nurse is preparing to give morphine 4 mg IV to a post-op patient. Respirations are 10/min. What should the nurse do first?', '[{"id":"a","text":"Give the medication as prescribed — pain increases respiratory rate"},{"id":"b","text":"Withhold the medication and notify the provider"},{"id":"c","text":"Give half the dose and reassess in 15 minutes"},{"id":"d","text":"Administer oxygen before giving morphine"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Opioids are withheld when respirations are <12/min due to the risk of respiratory depression. The nurse should hold the dose and notify the provider immediately. Naloxone (Narcan) should be available.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'Which electrolyte imbalance increases a patient''s risk of digoxin toxicity?', '[{"id":"a","text":"Hypernatremia"},{"id":"b","text":"Hypokalemia"},{"id":"c","text":"Hypermagnesemia"},{"id":"d","text":"Hypercalcemia"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Hypokalemia potentiates digoxin toxicity because potassium and digoxin compete for the same receptor (Na-K ATPase pump). Low potassium increases digoxin binding and effect. Monitor and maintain K+ 3.5–5.0 mEq/L.', '', '', '', 'published'),
  ('Pharmacology', 'sata', 'A nurse is caring for a patient receiving heparin infusion. Which findings indicate possible heparin-induced thrombocytopenia (HIT)? (Select all that apply)', '[{"id":"a","text":"Platelet count dropped from 280,000 to 90,000 on day 8 of therapy"},{"id":"b","text":"New thrombus formation despite heparin therapy"},{"id":"c","text":"aPTT supratherapeutic at 130 seconds"},{"id":"d","text":"Skin necrosis at heparin injection sites"},{"id":"e","text":"Serum potassium of 3.2 mEq/L"}]'::jsonb, '{"ids":["a","b","d"]}'::jsonb, 'HIT: >50% platelet drop on days 5–14, paradoxical new clotting, and skin necrosis at injection sites. Supratherapeutic aPTT reflects dosing, not HIT. Hypokalemia is unrelated. If HIT suspected, stop heparin immediately.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient with a penicillin allergy (hives) is prescribed cefazolin. What is the most appropriate nursing action?', '[{"id":"a","text":"Administer as prescribed — cephalosporins are unrelated to penicillin"},{"id":"b","text":"Hold the medication and verify the order with the provider"},{"id":"c","text":"Give a test dose and observe for 30 minutes"},{"id":"d","text":"Substitute oral amoxicillin instead"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'There is a small but real cross-reactivity between penicillins and cephalosporins (~1–2%). A penicillin allergy warrants clarification before administering a cephalosporin. The nurse should hold and verify. Amoxicillin is also a penicillin.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A nurse is administering IV potassium chloride 40 mEq. Which action is most important?', '[{"id":"a","text":"Administer by IV push over 2 minutes"},{"id":"b","text":"Dilute and infuse no faster than 10 mEq/hour peripherally"},{"id":"c","text":"Add to a 50 mL bag and give over 15 minutes"},{"id":"d","text":"Give orally instead to reduce cardiac risk"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'IV potassium must NEVER be given as a bolus — this causes fatal cardiac dysrhythmias. Maximum peripheral rate is 10 mEq/hr; central line max is 20 mEq/hr. Always dilute and monitor cardiac rhythm.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient on isoniazid (INH) for tuberculosis reports numbness and tingling in the feet. Which supplement should the nurse anticipate administering?', '[{"id":"a","text":"Vitamin C"},{"id":"b","text":"Pyridoxine (Vitamin B6)"},{"id":"c","text":"Folate"},{"id":"d","text":"Vitamin D"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'INH causes peripheral neuropathy by interfering with pyridoxine (B6) metabolism. Vitamin B6 supplementation is given prophylactically or to treat neuropathy in patients on INH, especially malnourished patients and the elderly.', '', '', '', 'published'),
  ('Pharmacology', 'sata', 'A nurse is reviewing medications for a patient prescribed MAOIs. Which substances should the patient avoid? (Select all that apply)', '[{"id":"a","text":"Aged cheeses"},{"id":"b","text":"Red wine"},{"id":"c","text":"Pseudoephedrine"},{"id":"d","text":"Fresh fruits"},{"id":"e","text":"Meperidine"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'MAOIs + tyramine-rich foods (aged cheese, red wine) → hypertensive crisis. MAOIs + sympathomimetics (pseudoephedrine) → hypertensive crisis. MAOIs + meperidine (Demerol) → serotonin syndrome or hyperpyrexic coma. Fresh fruits are safe.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A nurse is giving furosemide 40 mg IV. Which assessment finding requires immediate follow-up after administration?', '[{"id":"a","text":"Urine output 200 mL in the first hour"},{"id":"b","text":"Blood pressure decreased from 158/92 to 138/84"},{"id":"c","text":"Serum potassium dropped from 3.8 to 2.9 mEq/L"},{"id":"d","text":"Weight decreased by 0.5 kg"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Furosemide is a loop diuretic that wastes potassium. A drop to 2.9 mEq/L indicates hypokalemia (normal 3.5–5.0), which risks dangerous dysrhythmias. Potassium replacement should be initiated and the provider notified.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient taking methotrexate for rheumatoid arthritis calls to report mouth sores and a temperature of 38.6°C. What is the priority nursing response?', '[{"id":"a","text":"Advise the patient to use salt water rinses and monitor temperature"},{"id":"b","text":"Instruct the patient to go to the emergency department immediately"},{"id":"c","text":"Tell the patient to skip the next methotrexate dose"},{"id":"d","text":"Recommend acetaminophen and call back if temperature exceeds 39°C"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Methotrexate is an immunosuppressant. Fever with mucositis in an immunocompromised patient is a medical emergency — signs of severe bone marrow suppression and infection. The patient needs immediate evaluation and CBC.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'Which antidote should a nurse have available when administering IV magnesium sulfate?', '[{"id":"a","text":"Naloxone (Narcan)"},{"id":"b","text":"Protamine sulfate"},{"id":"c","text":"Calcium gluconate"},{"id":"d","text":"Flumazenil"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Calcium gluconate is the antidote for magnesium toxicity. Magnesium sulfate toxicity presents with absent reflexes, respiratory depression, and cardiac arrest. Calcium antagonizes magnesium''s CNS and neuromuscular effects.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient prescribed spironolactone asks what foods to limit. What should the nurse teach?', '[{"id":"a","text":"High-sodium foods"},{"id":"b","text":"High-potassium foods such as bananas and oranges"},{"id":"c","text":"High-fat foods"},{"id":"d","text":"Dairy products"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Spironolactone is a potassium-sparing diuretic. It retains potassium, so patients should limit high-potassium foods to prevent hyperkalemia (K+ >5.0 mEq/L), which causes dangerous dysrhythmias.', '', '', '', 'published'),
  ('Pharmacology', 'sata', 'A nurse is reviewing a patient''s medication list before administering the morning dose. Which medications require the nurse to take an apical pulse for one full minute before administration? (Select all that apply)', '[{"id":"a","text":"Digoxin"},{"id":"b","text":"Metoprolol"},{"id":"c","text":"Diltiazem"},{"id":"d","text":"Amlodipine"},{"id":"e","text":"Lisinopril"}]'::jsonb, '{"ids":["a","b","c"]}'::jsonb, 'Digoxin (cardiac glycoside), metoprolol (beta-blocker), and diltiazem (calcium channel blocker) all reduce heart rate — hold if apical pulse <60 bpm. Amlodipine (CCB) primarily reduces BP, not HR. Lisinopril (ACE inhibitor) does not significantly affect HR.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A nurse is preparing insulin. The order reads: "Regular insulin 10 units and NPH insulin 20 units subcutaneously." What is the correct preparation sequence?', '[{"id":"a","text":"Draw NPH first, then regular"},{"id":"b","text":"Draw regular first, then NPH"},{"id":"c","text":"Mix both in separate syringes and give two injections"},{"id":"d","text":"The order does not matter"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Memory aid: "Clear before cloudy." Regular insulin is clear; draw it first to prevent contaminating the regular vial with NPH (which is cloudy/modified). NPH contamination changes the action profile of regular insulin.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with chronic kidney disease has a serum potassium of 6.2 mEq/L and peaked T waves on ECG. Which intervention is the highest priority?', '[{"id":"a","text":"Administer sodium polystyrene sulfonate (Kayexalate) by mouth"},{"id":"b","text":"Prepare for emergent hemodialysis"},{"id":"c","text":"Administer IV calcium gluconate"},{"id":"d","text":"Start a low-potassium diet"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Peaked T waves with K+ 6.2 mEq/L indicates cardiac danger. IV calcium gluconate is given first to stabilize the cardiac membrane (does not lower K+ but prevents fatal arrhythmias). Then insulin/dextrose, Kayexalate, or dialysis to actually remove potassium.', '', '', '', 'published'),
  ('Medical-Surgical', 'sata', 'A nurse is caring for a patient with a pulmonary embolism (PE). Which findings are consistent with this diagnosis? (Select all that apply)', '[{"id":"a","text":"Sudden onset dyspnea"},{"id":"b","text":"Pleuritic chest pain"},{"id":"c","text":"Hemoptysis"},{"id":"d","text":"Bradycardia"},{"id":"e","text":"SpO2 88%"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'Classic PE triad: dyspnea, pleuritic chest pain, hemoptysis. Hypoxia (low SpO2) and tachycardia (not bradycardia) are expected. Bradycardia is not a PE finding — the compensatory response is tachycardia.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient returns from cardiac catheterization via the right femoral artery. Which assessment finding requires immediate action?', '[{"id":"a","text":"Pedal pulse 2+ in right foot"},{"id":"b","text":"Small bruise at insertion site"},{"id":"c","text":"Right groin hematoma expanding rapidly"},{"id":"d","text":"Patient reports needing to void"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'A rapidly expanding hematoma at the femoral access site indicates arterial bleeding — a vascular emergency. Apply firm manual pressure and notify the provider immediately. The patient may need emergent intervention.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with COPD is admitted with exacerbation. ABGs show pH 7.32, PaCO2 58, PaO2 62, HCO3 26. Which interpretation is correct?', '[{"id":"a","text":"Respiratory alkalosis"},{"id":"b","text":"Metabolic acidosis"},{"id":"c","text":"Respiratory acidosis, partially compensated"},{"id":"d","text":"Metabolic alkalosis"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'pH 7.32 (acidosis), PaCO2 58 (elevated → respiratory cause), HCO3 26 (slightly elevated → renal compensation). This is respiratory acidosis with partial metabolic compensation — classic COPD exacerbation with CO2 retention.', '', '', '', 'published'),
  ('Medical-Surgical', 'sata', 'A nurse is caring for a patient following a total hip replacement. Which actions help prevent hip dislocation? (Select all that apply)', '[{"id":"a","text":"Keep an abduction pillow between legs"},{"id":"b","text":"Avoid hip flexion beyond 90 degrees"},{"id":"c","text":"Encourage the patient to cross their legs when sitting"},{"id":"d","text":"Use a raised toilet seat"},{"id":"e","text":"Avoid internal rotation of the operative leg"}]'::jsonb, '{"ids":["a","b","d","e"]}'::jsonb, 'Hip dislocation precautions: abduction pillow to keep hips apart, no flexion >90°, use raised toilet seat, avoid internal rotation and adduction. Crossing legs causes adduction and internal rotation — strictly prohibited.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with a nasogastric tube connected to low intermittent suction develops muscle cramps and positive Chvostek''s sign. Which electrolyte imbalance should the nurse suspect?', '[{"id":"a","text":"Hyperkalemia"},{"id":"b","text":"Hypocalcemia"},{"id":"c","text":"Hypernatremia"},{"id":"d","text":"Hypomagnesemia"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Chvostek''s sign (facial twitching when tapping facial nerve) and Trousseau''s sign indicate hypocalcemia. NG suction removes gastric acid (HCl), causing metabolic alkalosis, which decreases ionized calcium. Monitor calcium levels.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with cirrhosis is confused and has asterixis (flapping tremor). Which diet modification is indicated?', '[{"id":"a","text":"High-protein diet to support liver regeneration"},{"id":"b","text":"Low-protein diet to reduce ammonia production"},{"id":"c","text":"High-fat diet to provide dense calories"},{"id":"d","text":"High-sodium diet to combat ascites"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Hepatic encephalopathy: confusion and asterixis result from elevated ammonia from protein metabolism. Limit dietary protein to reduce ammonia production. Lactulose and rifaximin are also used. Sodium restriction (not increase) manages ascites.', '', '', '', 'published'),
  ('Medical-Surgical', 'sata', 'A patient with acute pancreatitis is admitted. Which nursing interventions are appropriate? (Select all that apply)', '[{"id":"a","text":"NPO status initially to rest the pancreas"},{"id":"b","text":"IV fluid resuscitation"},{"id":"c","text":"Administer proton pump inhibitors"},{"id":"d","text":"Semi-Fowler''s or fetal position for comfort"},{"id":"e","text":"Encourage high-fat oral nutrition to restore weight"}]'::jsonb, '{"ids":["a","b","d"]}'::jsonb, 'Acute pancreatitis: NPO rests the pancreas, IV fluids prevent hypovolemia and necrosis, positioning (fetal or forward lean) relieves pain. PPIs are used for peptic ulcer disease not pancreatitis. High-fat foods worsen pancreatitis by stimulating pancreatic enzymes.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with a spinal cord injury at T4 suddenly develops a pounding headache, diaphoresis above the injury, and blood pressure of 218/114. What condition does the nurse suspect?', '[{"id":"a","text":"Hypertensive urgency from fluid overload"},{"id":"b","text":"Autonomic dysreflexia"},{"id":"c","text":"Neurogenic shock"},{"id":"d","text":"Spinal shock"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Autonomic dysreflexia is a life-threatening emergency in SCI at T6 or above. Triggers (full bladder, pressure ulcer) cause massive sympathetic response: severe hypertension, pounding headache, diaphoresis above lesion, bradycardia. Sit patient upright and remove the trigger immediately.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with deep vein thrombosis has a warm, swollen, painful right calf. Which action should the nurse avoid?', '[{"id":"a","text":"Elevating the affected extremity"},{"id":"b","text":"Massaging the affected leg to improve circulation"},{"id":"c","text":"Monitoring for signs of pulmonary embolism"},{"id":"d","text":"Administering anticoagulant therapy as ordered"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'NEVER massage a limb with suspected DVT — this can dislodge the clot, causing a pulmonary embolism. Elevation, anticoagulation, and monitoring for PE (dyspnea, chest pain, SpO2 drop) are appropriate interventions.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with a closed head injury has a GCS score of 8. What does this indicate?', '[{"id":"a","text":"Mild traumatic brain injury"},{"id":"b","text":"Normal neurological status"},{"id":"c","text":"Severe traumatic brain injury"},{"id":"d","text":"Moderate traumatic brain injury requiring monitoring"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Glasgow Coma Scale: 13–15 = mild TBI, 9–12 = moderate, ≤8 = severe TBI. GCS ≤8 typically indicates need for airway protection (intubation). The GCS evaluates eye opening, verbal, and motor responses (max 15, min 3).', '', '', '', 'published'),
  ('Medical-Surgical', 'sata', 'A patient is diagnosed with syndrome of inappropriate antidiuretic hormone (SIADH). Which findings does the nurse expect? (Select all that apply)', '[{"id":"a","text":"Serum sodium of 118 mEq/L"},{"id":"b","text":"Decreased urine output with concentrated urine"},{"id":"c","text":"Peripheral edema and hypertension"},{"id":"d","text":"Confusion and headache"},{"id":"e","text":"Increased serum osmolality"}]'::jsonb, '{"ids":["a","b","d"]}'::jsonb, 'SIADH: excess ADH causes water retention → dilutional hyponatremia (low Na+), concentrated urine (high urine osmolality), decreased serum osmolality. CNS symptoms (confusion, headache, seizures) from cerebral edema. No peripheral edema because fluid stays intracellular.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient post-thyroidectomy reports tingling around the mouth and carpopedal spasms. Which action is the nurse''s priority?', '[{"id":"a","text":"Administer IV calcium gluconate as ordered"},{"id":"b","text":"Apply oxygen via nasal cannula"},{"id":"c","text":"Draw a serum magnesium level"},{"id":"d","text":"Encourage the patient to breathe into a paper bag"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Post-thyroidectomy hypocalcemia occurs when the parathyroid glands are inadvertently removed or damaged (parathyroid glands regulate calcium). Tingling and carpopedal spasms (positive Trousseau''s sign) indicate hypocalcemia — treat with IV calcium gluconate.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A nurse is caring for a patient with a chest tube. The fluid in the water-seal chamber is fluctuating (tidaling) with respirations. What does this indicate?', '[{"id":"a","text":"A clot in the chest tube"},{"id":"b","text":"The system is functioning properly"},{"id":"c","text":"The lung has fully re-expanded"},{"id":"d","text":"Subcutaneous emphysema is developing"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Tidaling (fluid rising with inspiration, falling with expiration) in the water-seal chamber is NORMAL and indicates the chest tube is patent and functioning. Tidaling stops when the lung fully re-expands or if the tube is kinked/blocked.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with Addison''s disease is admitted with vomiting, hypotension, and severe fatigue. What is the priority intervention?', '[{"id":"a","text":"Oral hydrocortisone replacement"},{"id":"b","text":"IV hydrocortisone and isotonic saline"},{"id":"c","text":"Blood transfusion for hypovolemia"},{"id":"d","text":"Restrict fluids to prevent hyponatremia"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Addisonian crisis (acute adrenal insufficiency) is life-threatening. Priority: IV glucocorticoid (hydrocortisone) replacement and aggressive IV isotonic saline (0.9% NaCl) for sodium and volume replacement. Oral corticosteroids cannot be absorbed during vomiting crisis.', '', '', '', 'published'),
  ('Medical-Surgical', 'sata', 'A patient is admitted with acute kidney injury (AKI). Which findings indicate the oliguric phase? (Select all that apply)', '[{"id":"a","text":"Urine output <400 mL/day"},{"id":"b","text":"Rising BUN and creatinine"},{"id":"c","text":"Hyperkalemia"},{"id":"d","text":"Polyuria of 3–5 L/day"},{"id":"e","text":"Metabolic acidosis"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'Oliguric phase of AKI: <400 mL urine/day, rising BUN/creatinine (uremia), hyperkalemia (kidney can''t excrete K+), and metabolic acidosis (kidney can''t excrete H+). Polyuria (3–5 L/day) occurs in the diuretic phase that follows recovery.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with a burns covering 30% TBSA is in the emergent phase. Using the Parkland Formula, how much fluid should be given in the first 8 hours? (Patient weighs 70 kg)', '[{"id":"a","text":"2,100 mL"},{"id":"b","text":"4,200 mL"},{"id":"c","text":"8,400 mL"},{"id":"d","text":"1,050 mL"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Parkland Formula: 4 mL × kg × %TBSA = 4 × 70 × 30 = 8,400 mL total in 24 hrs. Give half (4,200 mL) in the first 8 hours, and the remaining 4,200 mL over the next 16 hours. Count from time of burn, not admission.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A nurse is caring for a patient with increased intracranial pressure. Which position is most appropriate?', '[{"id":"a","text":"Trendelenburg position"},{"id":"b","text":"Head of bed elevated 30 degrees, neck in neutral alignment"},{"id":"c","text":"Prone position to reduce venous pooling"},{"id":"d","text":"Head of bed flat to maintain cerebral perfusion"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'HOB 30° promotes venous drainage from the brain, reducing ICP. Keep neck neutral (no flexion or rotation) to prevent jugular vein compression. Trendelenburg and flat positions increase ICP by impeding venous outflow.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with type 1 diabetes develops diaphoresis, trembling, and a blood glucose of 48 mg/dL. The patient is conscious and able to swallow. What is the priority action?', '[{"id":"a","text":"Administer 1 mg glucagon intramuscularly"},{"id":"b","text":"Give 15 grams of fast-acting carbohydrates orally"},{"id":"c","text":"Administer 50 mL of D50W IV"},{"id":"d","text":"Call the provider and wait for orders"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Rule of 15: give 15g fast carbs (4 oz juice, glucose tablets) → wait 15 min → recheck glucose. For a conscious patient who can swallow, oral carbs are first-line. IV D50 and IM glucagon are for unconscious patients who cannot swallow.', '', '', '', 'published'),
  ('Medical-Surgical', 'sata', 'A patient has a hemoglobin of 7.2 g/dL and is receiving a packed red blood cell transfusion. Which findings require the nurse to stop the transfusion immediately? (Select all that apply)', '[{"id":"a","text":"Temperature increase of 1.5°C"},{"id":"b","text":"Low back pain and chills within 15 minutes of starting"},{"id":"c","text":"Mild urticaria (hives) localized to the arm"},{"id":"d","text":"New-onset dyspnea and oxygen saturation drop to 88%"},{"id":"e","text":"Slight redness at the IV site"}]'::jsonb, '{"ids":["b","d"]}'::jsonb, 'Stop transfusion for: low back pain + chills (hemolytic reaction — medical emergency), dyspnea + SpO2 drop (TRALI or TACO). Mild fever or urticaria = slow or stop, give antipyretics/diphenhydramine, may resume. Local IV site redness needs site care but not transfusion stoppage.', '', '', '', 'published'),
  ('Mental Health', 'mcq', 'A patient with schizophrenia states, "The TV is sending me special messages." This is an example of:', '[{"id":"a","text":"Hallucination"},{"id":"b","text":"Delusion of reference"},{"id":"c","text":"Thought broadcasting"},{"id":"d","text":"Negative symptom"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'A delusion of reference is the false belief that ordinary events have special personal meaning directed at the individual. Hallucinations are sensory perceptions without stimuli. Thought broadcasting is the belief others can hear your thoughts.', '', '', '', 'published'),
  ('Mental Health', 'mcq', 'A patient threatens to leave the hospital against medical advice. The nurse restrains the patient without consent. This constitutes:', '[{"id":"a","text":"Battery"},{"id":"b","text":"False imprisonment"},{"id":"c","text":"Negligence"},{"id":"d","text":"Malpractice"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'False imprisonment is unlawful restraint or restriction of a person''s freedom of movement without consent or legal justification. Patients who are competent and have decision-making capacity have the right to leave AMA. The nurse should document the AMA discussion.', '', '', '', 'published'),
  ('Mental Health', 'sata', 'A nurse is assessing suicide risk. Which factors significantly increase risk? (Select all that apply)', '[{"id":"a","text":"Previous suicide attempt"},{"id":"b","text":"Access to lethal means such as firearms"},{"id":"c","text":"Strong religious beliefs against suicide"},{"id":"d","text":"Recent significant loss or humiliation"},{"id":"e","text":"Stated desire for revenge"}]'::jsonb, '{"ids":["a","b","d"]}'::jsonb, 'Highest risk factors: prior attempt (strongest predictor), access to means (especially firearms), recent loss/humiliation. Strong religious beliefs and social support are protective factors that reduce risk. Expressed desire for revenge alone is insufficient for elevated risk categorization.', '', '', '', 'published'),
  ('Mental Health', 'mcq', 'A patient in the manic phase of bipolar disorder refuses to eat because "eating takes too much time." What is the most therapeutic nursing response?', '[{"id":"a","text":"Sit with the patient during structured mealtimes and encourage eating"},{"id":"b","text":"Offer high-calorie finger foods and snacks the patient can eat while moving"},{"id":"c","text":"Restrict activities until the patient agrees to sit and eat a full meal"},{"id":"d","text":"Notify the provider that the patient is refusing meals"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Manic patients are hyperactive and cannot sit still for meals. Provide portable, high-calorie finger foods (sandwiches, crackers, fruit) so they can eat while moving. This meets nutritional needs within the patient''s behavioral capacity during mania.', '', '', '', 'published'),
  ('Mental Health', 'mcq', 'A patient prescribed clozapine (Clozaril) requires monitoring for which serious adverse effect?', '[{"id":"a","text":"QT prolongation"},{"id":"b","text":"Agranulocytosis"},{"id":"c","text":"Tardive dyskinesia"},{"id":"d","text":"Neuroleptic malignant syndrome"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Clozapine has a BLACK BOX WARNING for agranulocytosis (life-threatening drop in WBC/neutrophils). Weekly then bi-weekly ANC monitoring is mandatory. The drug is only available through a restricted REMS program. Hold if ANC <1500.', '', '', '', 'published'),
  ('Mental Health', 'mcq', 'A patient experiencing alcohol withdrawal on day 2 develops tremors, diaphoresis, and a seizure. Which medication does the nurse anticipate?', '[{"id":"a","text":"Haloperidol (Haldol)"},{"id":"b","text":"Lorazepam (Ativan)"},{"id":"c","text":"Naltrexone (Vivitrol)"},{"id":"d","text":"Disulfiram (Antabuse)"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Benzodiazepines (lorazepam, diazepam) are first-line for alcohol withdrawal seizures and delirium tremens. They cross-react with GABA receptors to prevent CNS hyperexcitability. CIWA-Ar protocol guides dosing. Haloperidol lowers seizure threshold.', '', '', '', 'published'),
  ('Mental Health', 'sata', 'A nurse is applying therapeutic communication with a patient who is grieving. Which responses are therapeutic? (Select all that apply)', '[{"id":"a","text":"\"I understand exactly how you feel.\""},{"id":"b","text":"\"Tell me what you''re experiencing right now.\""},{"id":"c","text":"\"This must be a very difficult time for you.\""},{"id":"d","text":"\"Everything happens for a reason.\""},{"id":"e","text":"Sitting silently with the patient for several minutes"}]'::jsonb, '{"ids":["b","c","e"]}'::jsonb, 'Therapeutic: open-ended questions, empathy, and therapeutic silence. Non-therapeutic: "I know how you feel" (impossible to know another''s experience — blocks communication) and clichés like "everything happens for a reason" (minimizes feelings).', '', '', '', 'published'),
  ('Mental Health', 'mcq', 'A patient with anorexia nervosa has a BMI of 15.2 and serum potassium of 2.8 mEq/L. What is the priority concern?', '[{"id":"a","text":"Cardiac dysrhythmias from electrolyte imbalance"},{"id":"b","text":"Impaired body image and self-esteem"},{"id":"c","text":"Risk of refeeding syndrome from rapid nutritional replacement"},{"id":"d","text":"Social isolation related to disordered eating behaviors"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'With K+ 2.8 mEq/L, the priority is physiologic safety — hypokalemia causes life-threatening cardiac dysrhythmias including ventricular fibrillation. The body can only address psychosocial needs once the patient is medically stabilized.', '', '', '', 'published'),
  ('Mental Health', 'mcq', 'A patient with PTSD wakes up screaming and is disoriented. What is the nurse''s therapeutic response?', '[{"id":"a","text":"\"You''re safe. I''m your nurse. You''re in the hospital.\""},{"id":"b","text":"\"Calm down. It was just a dream.\""},{"id":"c","text":"Leave the room to give the patient space"},{"id":"d","text":"Ask the patient to describe the nightmare in detail"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'During a PTSD nightmare/flashback, orient the patient with calm, simple statements about safety and present reality. "You''re safe, you''re in the hospital" grounds the patient. Dismissing the experience or leaving is non-therapeutic; detail-seeking during acute distress is re-traumatizing.', '', '', '', 'published'),
  ('Mental Health', 'mcq', 'A patient receiving an SSRI for 10 days reports feeling more energetic and has made end-of-life phone calls to family. What is the priority nursing concern?', '[{"id":"a","text":"The SSRI is working — energy returning is a positive sign"},{"id":"b","text":"The patient may be at increased risk for suicide"},{"id":"c","text":"The SSRI needs to be increased as the patient still seems sad"},{"id":"d","text":"Teach the patient it takes 4–6 weeks for full effect"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'SSRIs restore energy before improving mood — patients may now have enough motivation to act on suicidal thoughts. "End-of-life" calls (saying goodbye) and increased energy in the first 2 weeks = HIGH RISK for suicide. Perform a complete safety assessment immediately.', '', '', '', 'published'),
  ('Maternal and Newborn', 'mcq', 'A nurse is monitoring a patient in active labor. Which fetal heart rate pattern requires immediate intervention?', '[{"id":"a","text":"Early decelerations beginning and ending with contractions"},{"id":"b","text":"Accelerations with fetal movement"},{"id":"c","text":"Late decelerations occurring after each contraction"},{"id":"d","text":"Variable decelerations that resolve quickly"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Late decelerations (FHR drops after the peak of a contraction and recovers late) indicate uteroplacental insufficiency — fetal hypoxia. Immediate actions: left lateral position, O2 via mask, IV fluids, stop oxytocin, notify provider. Early decelerations are benign (head compression). Accelerations are reassuring.', '', '', '', 'published'),
  ('Maternal and Newborn', 'sata', 'A nurse is caring for a patient at 38 weeks gestation with severe preeclampsia (BP 168/112). Which interventions are priority? (Select all that apply)', '[{"id":"a","text":"Administer magnesium sulfate IV as ordered"},{"id":"b","text":"Maintain a quiet, low-stimulation environment"},{"id":"c","text":"Monitor reflexes, LOC, and respiratory rate hourly"},{"id":"d","text":"Encourage ambulation in the hallway to lower BP"},{"id":"e","text":"Keep calcium gluconate at bedside"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'Severe preeclampsia: mag sulfate prevents seizures (eclampsia), low-stimulation prevents seizure triggers, close monitoring of mag toxicity signs (absent reflexes, RR <12, LOC), calcium gluconate is the mag sulfate antidote. Ambulation is contraindicated — bedrest.', '', '', '', 'published'),
  ('Maternal and Newborn', 'mcq', 'A breastfeeding mother asks the nurse when her milk will "come in" after birth. What is the most accurate response?', '[{"id":"a","text":"Within 2–4 hours of delivery"},{"id":"b","text":"Day 3–5 postpartum"},{"id":"c","text":"At 2 weeks postpartum"},{"id":"d","text":"Only after the placenta is delivered"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Colostrum (thick, yellow, antibody-rich) is produced for the first 2–3 days. Mature breast milk transitions in at 3–5 days postpartum. Teach the mother this is normal and that colostrum alone adequately nourishes the newborn in the first days.', '', '', '', 'published'),
  ('Maternal and Newborn', 'mcq', 'A nurse assesses a postpartum patient 1 hour after delivery and finds the fundus boggy and displaced to the right. What is the priority action?', '[{"id":"a","text":"Document and continue monitoring"},{"id":"b","text":"Have the patient void and then reassess the fundus"},{"id":"c","text":"Perform firm uterine massage immediately"},{"id":"d","text":"Administer oxytocin (Pitocin) as ordered"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'A full bladder displaces the uterus (usually to the right) and prevents proper contraction, causing uterine atony and bleeding. First: have the patient void or catheterize, then reassess. A boggy fundus = uterine atony = risk of postpartum hemorrhage.', '', '', '', 'published'),
  ('Maternal and Newborn', 'mcq', 'A newborn is born at 35 weeks gestation. Which finding is most expected compared to a term newborn?', '[{"id":"a","text":"Strong suck and swallow reflex"},{"id":"b","text":"Lanugo covering most of the body"},{"id":"c","text":"Abundant vernix only in skin folds"},{"id":"d","text":"Well-developed plantar creases"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Lanugo (fine hair covering) is abundant in preterm infants and diminishes as gestation advances. At 35 weeks: poor suck/swallow (weak), abundant lanugo, decreased vernix (it builds up then decreases), and few plantar creases (those develop in the 3rd trimester).', '', '', '', 'published'),
  ('Maternal and Newborn', 'sata', 'A nurse is caring for a newborn receiving phototherapy for jaundice. Which interventions are appropriate? (Select all that apply)', '[{"id":"a","text":"Cover the newborn''s eyes with opaque shields"},{"id":"b","text":"Remove eye shields during feedings for bonding"},{"id":"c","text":"Monitor temperature frequently"},{"id":"d","text":"Apply lotion to skin to prevent drying"},{"id":"e","text":"Increase feeding frequency to promote bilirubin excretion"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'Phototherapy: opaque eye shields protect retinas, remove during feedings for parent bonding, frequent temp monitoring (lights cause hyperthermia/hypothermia), frequent feedings promote GI transit and bilirubin excretion. Do NOT apply lotions — increases risk of burns under lights.', '', '', '', 'published'),
  ('Maternal and Newborn', 'mcq', 'A patient at 32 weeks gestation reports sudden, painless, bright red vaginal bleeding. Which condition does the nurse suspect?', '[{"id":"a","text":"Placental abruption"},{"id":"b","text":"Placenta previa"},{"id":"c","text":"Preterm labor"},{"id":"d","text":"Ruptured uterus"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Placenta previa: painless, bright red bleeding (placenta covers the cervical os, bleeds as cervix dilates). Placental abruption: sudden, painful, dark red bleeding. NEVER perform a vaginal exam in placenta previa — can cause massive hemorrhage. Immediate bedrest and notify provider.', '', '', '', 'published'),
  ('Maternal and Newborn', 'mcq', 'A nurse notices a newborn has a bluish-purple bruise-like discoloration on the lower back and buttocks. What is this finding?', '[{"id":"a","text":"Sign of child abuse requiring immediate reporting"},{"id":"b","text":"Mongolian spot — a normal finding in darker-skinned newborns"},{"id":"c","text":"Hemangioma requiring dermatology consultation"},{"id":"d","text":"Port-wine stain associated with Sturge-Weber syndrome"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Mongolian spots (congenital dermal melanocytosis) are blue-gray pigmented areas on the sacral/lumbar region, common in Asian, Hispanic, Native American, and Black newborns. They are benign and typically fade by school age. Important to document to prevent later confusion with bruising.', '', '', '', 'published'),
  ('Pediatrics', 'mcq', 'A nurse is caring for a 4-year-old post-tonsillectomy. Which assessment finding requires immediate action?', '[{"id":"a","text":"Reports throat pain rated 5/10"},{"id":"b","text":"Frequent swallowing and restlessness"},{"id":"c","text":"Refuses to drink cold fluids"},{"id":"d","text":"Low-grade temperature of 37.8°C"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Frequent swallowing in a post-tonsillectomy child is a classic early sign of hemorrhage — the child is swallowing blood. Assess the throat immediately. This is a surgical emergency. Throat pain, fluid refusal, and low-grade fever are expected post-tonsillectomy findings.', '', '', '', 'published'),
  ('Pediatrics', 'sata', 'A nurse is educating parents on preventing sudden infant death syndrome (SIDS). Which recommendations should be included? (Select all that apply)', '[{"id":"a","text":"Place baby on their back to sleep"},{"id":"b","text":"Use a firm, flat sleep surface"},{"id":"c","text":"Keep the sleep area free of soft objects and loose bedding"},{"id":"d","text":"Allow the baby to sleep in the parents'' bed for warmth"},{"id":"e","text":"Offer a pacifier at sleep time after breastfeeding is established"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'Safe sleep (AAP): back to sleep, firm flat surface, no soft objects/bedding. Pacifier use reduces SIDS risk — offer after breastfeeding is established (3–4 weeks). Bed-sharing (co-sleeping) increases SIDS risk significantly and is NOT recommended.', '', '', '', 'published'),
  ('Pediatrics', 'mcq', 'A 2-year-old is brought to the ED with inspiratory stridor, a barking cough, and low-grade fever. Which condition is most likely?', '[{"id":"a","text":"Epiglottitis"},{"id":"b","text":"Croup (laryngotracheobronchitis)"},{"id":"c","text":"Bronchiolitis"},{"id":"d","text":"Asthma"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Croup: barking/seal-like cough, inspiratory stridor, low-grade fever in children 6 months–3 years, often worsens at night. Epiglottitis: "tripod position," drooling, high fever, NO barking cough — do not examine throat. Bronchiolitis: expiratory wheezing, RSV, <2 years.', '', '', '', 'published'),
  ('Pediatrics', 'mcq', 'The parent of a 9-month-old asks when to introduce solid foods. The nurse''s best response is:', '[{"id":"a","text":"\"Start solids at 4 months to help the baby sleep longer.\""},{"id":"b","text":"\"Solids should be introduced between 4–6 months, and your baby appears ready.\""},{"id":"c","text":"\"Wait until 12 months to reduce allergy risk.\""},{"id":"d","text":"\"Single-grain iron-fortified cereals are introduced around 6 months with developmental readiness signs.\""}]'::jsonb, '{"ids":["d"]}'::jsonb, 'AAP recommends introducing solid foods around 6 months with signs of readiness: sitting with support, good head control, interest in food, loss of tongue-thrust reflex. Iron-fortified single-grain cereals and pureed vegetables/fruits are appropriate first foods.', '', '', '', 'published'),
  ('Pediatrics', 'mcq', 'A 6-year-old with acute asthma exacerbation has SpO2 of 91%, is using accessory muscles, and speaks in short phrases. What is the priority intervention?', '[{"id":"a","text":"Administer a short-acting beta2 agonist (albuterol) via nebulizer"},{"id":"b","text":"Obtain a chest X-ray to rule out pneumonia"},{"id":"c","text":"Apply supplemental oxygen and complete full nursing assessment"},{"id":"d","text":"Administer oral corticosteroids"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Priority in acute asthma: bronchodilator first (albuterol via nebulizer/MDI) to reverse bronchoconstriction. SpO2 91% with accessory muscle use and limited speech indicates moderate-severe exacerbation. Oxygen, corticosteroids follow, but bronchodilation is the urgent intervention.', '', '', '', 'published'),
  ('Pediatrics', 'sata', 'A nurse suspects child abuse in a 3-year-old admitted with multiple bruises. Which findings increase this suspicion? (Select all that apply)', '[{"id":"a","text":"Bruises in various stages of healing"},{"id":"b","text":"Bruises on the shins and knees of an ambulatory child"},{"id":"c","text":"Patterned bruising (shape of belt buckle, cord)"},{"id":"d","text":"Inconsistent story between caregiver and child"},{"id":"e","text":"Bruising over bony prominences"}]'::jsonb, '{"ids":["a","c","d"]}'::jsonb, 'Red flags for abuse: bruises in multiple healing stages (different-colored), patterned injuries (burns, bite marks, belt shapes), inconsistent history. Bruises on shins/knees and bony prominences are normal in active toddlers. Mandated reporters must report ALL suspected abuse.', '', '', '', 'published'),
  ('Pediatrics', 'mcq', 'A 7-year-old with type 1 diabetes has a blood glucose of 380 mg/dL, is vomiting, and has Kussmaul breathing. What is the priority nursing action?', '[{"id":"a","text":"Give a rapidly absorbed carbohydrate snack"},{"id":"b","text":"Establish IV access and prepare for IV insulin and fluids"},{"id":"c","text":"Administer glucagon IM"},{"id":"d","text":"Place in Trendelenburg to increase cerebral perfusion"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'DKA in a child: hyperglycemia + vomiting + Kussmaul breathing (metabolic acidosis compensation) = pediatric emergency. IV access for fluid resuscitation (normal saline) and continuous IV insulin are priorities. Oral carbs worsen hyperglycemia; glucagon treats hypoglycemia.', '', '', '', 'published'),
  ('Pediatrics', 'mcq', 'A 12-month-old has not yet said "mama" or "dada" specifically. What is the nurse''s response?', '[{"id":"a","text":"Reassure the parents this is within normal limits"},{"id":"b","text":"Refer for developmental evaluation — should have 2–4 words by 12 months"},{"id":"c","text":"Recommend speech therapy immediately"},{"id":"d","text":"Advise recheck at 15 months if no words develop"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'By 12 months, children should have 2–4 meaningful words (not just babbling). Absence of these words is a developmental red flag. Early referral for evaluation is preferred — early speech therapy intervention has the best outcomes. Do not wait until 15 months.', '', '', '', 'published'),
  ('Safety and Infection Control', 'mcq', 'A nurse is preparing to insert a urinary catheter. Which action best prevents catheter-associated urinary tract infections (CAUTI)?', '[{"id":"a","text":"Change the catheter every 7 days"},{"id":"b","text":"Use strict sterile technique during insertion"},{"id":"c","text":"Irrigate the catheter daily with normal saline"},{"id":"d","text":"Apply antibiotic ointment to the urethral meatus daily"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Strict sterile technique during catheter insertion is the most effective CAUTI prevention strategy. Also: use smallest gauge catheter, remove as soon as possible, maintain closed drainage system, keep bag below bladder. Routine catheter changes, irrigation, and meatal ointment are not evidence-based for CAUTI prevention.', '', '', '', 'published'),
  ('Safety and Infection Control', 'sata', 'A patient is placed on neutropenic precautions after chemotherapy. Which actions are appropriate? (Select all that apply)', '[{"id":"a","text":"Provide a low-microbial (neutropenic) diet avoiding raw fruits and vegetables"},{"id":"b","text":"Place patient in a private room with positive-pressure air flow"},{"id":"c","text":"Restrict all visitors"},{"id":"d","text":"Monitor temperature every 4 hours"},{"id":"e","text":"Perform meticulous hand hygiene before entering room"}]'::jsonb, '{"ids":["a","b","d","e"]}'::jsonb, 'Neutropenic precautions: low-microbial diet, positive-pressure private room (protects patient FROM environment), frequent temperature monitoring (fever = infection emergency in neutropenic patient), meticulous hand hygiene. Visitors are restricted (no ill visitors) but not eliminated entirely.', '', '', '', 'published'),
  ('Safety and Infection Control', 'mcq', 'A nurse sustains a needlestick from a patient with unknown HIV status. What is the priority action?', '[{"id":"a","text":"Complete an incident report and see occupational health within 72 hours"},{"id":"b","text":"Immediately wash the site thoroughly with soap and water, then report to employee health"},{"id":"c","text":"Squeeze the wound to expel blood and apply antiseptic"},{"id":"d","text":"Begin prophylactic antibiotics immediately"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Immediate action after needlestick: wash site with soap and water thoroughly. Then report immediately to employee health for exposure assessment, testing of source patient (if available), and decision on post-exposure prophylaxis (PEP) — must start within 72 hours of exposure for HIV. Do NOT squeeze wound (increases tissue trauma).', '', '', '', 'published'),
  ('Safety and Infection Control', 'mcq', 'A patient with active pulmonary tuberculosis (TB) requires which type of precautions?', '[{"id":"a","text":"Contact precautions: gown and gloves"},{"id":"b","text":"Droplet precautions: surgical mask within 3 feet"},{"id":"c","text":"Airborne precautions: negative-pressure room and N95 respirator"},{"id":"d","text":"Standard precautions only"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'TB is transmitted via airborne droplet nuclei (<5 microns) that remain suspended in air. Requires: negative-pressure isolation room, N95 (not surgical mask) for all who enter, door kept closed. Patient transport: have patient wear surgical mask. Standard masks do NOT filter TB particles.', '', '', '', 'published'),
  ('Safety and Infection Control', 'sata', 'A nurse is preparing to change a central line dressing using the CLABSI bundle. Which interventions are included? (Select all that apply)', '[{"id":"a","text":"Hand hygiene before the procedure"},{"id":"b","text":"Use chlorhexidine gluconate for skin antisepsis"},{"id":"c","text":"Use sterile technique with mask, gown, and sterile gloves"},{"id":"d","text":"Change tubing every 24 hours"},{"id":"e","text":"Daily assessment of whether the central line is still needed"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'CLABSI bundle: hand hygiene, maximal sterile barrier precautions, chlorhexidine (CHG) skin antisepsis, optimal site selection, daily review of line necessity. Standard IV tubing is changed every 72–96 hours (not 24h). Lipid tubing changes every 24 hours.', '', '', '', 'published'),
  ('Safety and Infection Control', 'mcq', 'A nurse is caring for a patient with MRSA in a wound. Which PPE should be donned before entering the room?', '[{"id":"a","text":"N95 respirator and gloves"},{"id":"b","text":"Gown and gloves"},{"id":"c","text":"Surgical mask, gown, and gloves"},{"id":"d","text":"Gloves only for direct wound contact"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'MRSA requires contact precautions: gown and gloves upon room entry. A mask is not required for MRSA wound infections (MRSA is not airborne). A mask would be added for procedures generating respiratory secretions. Gloves alone are insufficient — gown prevents clothing contamination.', '', '', '', 'published'),
  ('Safety and Infection Control', 'mcq', 'A nurse is assessing a patient''s fall risk using the Morse Fall Scale. Which factor contributes most to a high score?', '[{"id":"a","text":"Age over 65"},{"id":"b","text":"History of a fall in the past 3 months"},{"id":"c","text":"Impaired gait requiring a walker"},{"id":"d","text":"Use of diuretic medication"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'The Morse Fall Scale scores: history of falling (25 points — highest single item), secondary diagnosis, ambulatory aid, IV or heparin lock, gait, and mental status. A prior fall is the strongest predictor of future falls. Implement high-risk fall precautions for scores ≥45.', '', '', '', 'published'),
  ('Leadership and Management', 'mcq', 'A nurse has four patients. Which patient should be assessed first?', '[{"id":"a","text":"A patient with chronic back pain requesting pain medication"},{"id":"b","text":"A post-op patient with oxygen saturation of 90% reported by the UAP"},{"id":"c","text":"A stable patient with diabetes asking about diet instructions"},{"id":"d","text":"A patient awaiting discharge with prescription questions"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Airway/oxygenation is always priority. SpO2 90% is below normal (95–100%) and may indicate respiratory compromise — assess immediately. Chronic pain, diet teaching, and discharge questions are lower acuity. Apply ABC (Airway, Breathing, Circulation) and Maslow''s hierarchy to prioritize.', '', '', '', 'published'),
  ('Leadership and Management', 'sata', 'A charge nurse is delegating tasks to a UAP. Which tasks are within the UAP''s scope of practice? (Select all that apply)', '[{"id":"a","text":"Measuring and recording urine output"},{"id":"b","text":"Ambulating a stable post-op patient"},{"id":"c","text":"Administering a PRN enema"},{"id":"d","text":"Obtaining vital signs on stable patients"},{"id":"e","text":"Performing a focused respiratory assessment"}]'::jsonb, '{"ids":["a","b","d"]}'::jsonb, 'UAPs may perform: vital signs on stable patients, measuring I&O, feeding, ambulating stable patients, hygiene, positioning. UAPs may NOT: assessments (physical, focused, or otherwise), medication administration, IV care, or care requiring clinical judgment. Enemas require RN order and assessment of response.', '', '', '', 'published'),
  ('Leadership and Management', 'mcq', 'A nurse discovers a medication error made by the previous shift. The patient is unharmed. What is the nurse''s priority action?', '[{"id":"a","text":"Confront the nurse who made the error"},{"id":"b","text":"Assess the patient, notify the provider, and complete an incident report"},{"id":"c","text":"Document the error in the patient''s chart in detail"},{"id":"d","text":"Report the error to the state board of nursing immediately"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Medication error response: 1) Assess patient, 2) Notify the provider of the error and patient status, 3) Complete an internal incident/variance report (this is NOT documented in the patient''s medical record in detail). State board reporting is for patterns of unsafe practice, not individual unharmed errors.', '', '', '', 'published'),
  ('Leadership and Management', 'mcq', 'A nurse is using SBAR to communicate with a physician. What information is included in the "B" (Background) component?', '[{"id":"a","text":"The nurse''s recommendation for treatment"},{"id":"b","text":"Current vital signs and what changed recently"},{"id":"c","text":"Pertinent medical history and reason for admission"},{"id":"d","text":"The patient''s name, age, and why the nurse is calling"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'SBAR: S=Situation (who, what, why calling), B=Background (diagnosis, history, relevant labs/meds), A=Assessment (what the nurse thinks is happening), R=Recommendation (what the nurse is requesting). Background provides clinical context for the current situation.', '', '', '', 'published'),
  ('Leadership and Management', 'sata', 'A nurse manager is addressing staff burnout. Which evidence-based strategies are effective? (Select all that apply)', '[{"id":"a","text":"Implement consistent scheduling with adequate days off"},{"id":"b","text":"Provide mandatory overtime to increase unit staffing"},{"id":"c","text":"Create a culture of psychological safety for reporting concerns"},{"id":"d","text":"Offer access to employee assistance programs"},{"id":"e","text":"Conduct regular team debriefs after difficult patient events"}]'::jsonb, '{"ids":["a","c","d","e"]}'::jsonb, 'Burnout prevention: adequate rest (consistent scheduling), psychological safety (reduces moral injury), EAP access (mental health resources), and debriefing after critical incidents. Mandatory overtime is a primary CAUSE of burnout and has been shown to increase errors and turnover.', '', '', '', 'published'),
  ('Leadership and Management', 'mcq', 'A nurse receives an order to administer a medication that the nurse believes is inappropriate for the patient. What is the correct sequence of actions?', '[{"id":"a","text":"Administer the medication because the provider is ultimately responsible"},{"id":"b","text":"Refuse to give the medication and document the refusal without notifying anyone"},{"id":"c","text":"Question the order with the provider, and if unresolved, follow the chain of command"},{"id":"d","text":"Give the medication but document the nurse''s concerns"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Nurses are legally and ethically accountable for every medication they administer. If a medication seems inappropriate: question the provider, seek clarification. If unresolved, follow the chain of command (charge nurse → supervisor → medical director). Document the process. "I was just following orders" is not a legal defense.', '', '', '', 'published'),
  ('Leadership and Management', 'mcq', 'A newly licensed nurse is overwhelmed and makes a medication error. The charge nurse''s best response is:', '[{"id":"a","text":"Report the nurse to the nursing board for endangering patient safety"},{"id":"b","text":"Publicly address the error at the nurses'' station to deter future mistakes"},{"id":"c","text":"Conduct a private conversation focused on learning and system improvements"},{"id":"d","text":"Document the error in the nurse''s personnel file without discussion"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'A just culture approach: address errors privately, focus on learning not blame, examine systems that contributed (staffing, distractions, process gaps). Public shaming and immediate punitive action without context worsen psychological safety and increase future error rates. Support from preceptors reduces new-nurse turnover.', '', '', '', 'published'),
  ('NGN Case Studies', 'mcq', 'A nurse is caring for a 68-year-old with heart failure. The patient reports weight gain of 4 pounds in 2 days, increased ankle swelling, and cannot lie flat without "air hunger." Which nursing action is the highest priority?', '[{"id":"a","text":"Administer scheduled furosemide and reassess in 2 hours"},{"id":"b","text":"Elevate legs to reduce ankle edema"},{"id":"c","text":"Notify the provider immediately — patient is decompensating"},{"id":"d","text":"Obtain daily weight and compare to baseline"}]'::jsonb, '{"ids":["c"]}'::jsonb, '4-pound weight gain in 2 days + orthopnea + edema = acute decompensated heart failure. This requires immediate provider notification for possible IV diuresis, BNP, echo, or hospitalization. Orthopnea (inability to lie flat due to dyspnea) indicates significant pulmonary congestion.', '', '', '', 'published'),
  ('NGN Case Studies', 'sata', 'A nurse reviews a patient''s chart: 55-year-old, 3 days post-op colectomy, T 39.1°C, HR 108, BP 88/56, RR 24, WBC 18,000. Which findings indicate the patient may be developing sepsis? (Select all that apply)', '[{"id":"a","text":"Temperature 39.1°C"},{"id":"b","text":"HR 108 bpm"},{"id":"c","text":"BP 88/56 mmHg"},{"id":"d","text":"WBC 18,000"},{"id":"e","text":"RR 24 breaths/min"}]'::jsonb, '{"ids":["a","b","c","d","e"]}'::jsonb, 'qSOFA/SIRS criteria for sepsis: temp >38 or <36°C, HR >90, RR >20, WBC >12,000 or <4,000. This patient meets all criteria with hypotension (BP 88/56) suggesting septic shock. Activate rapid response/sepsis protocol immediately. Time is critical — 1-hour bundle.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient with peptic ulcer disease is prescribed omeprazole. When should this medication be administered?', '[{"id":"a","text":"30–60 minutes before breakfast"},{"id":"b","text":"With meals to reduce gastric upset"},{"id":"c","text":"At bedtime for maximum effect"},{"id":"d","text":"With antacids to enhance absorption"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Proton pump inhibitors (omeprazole) must be taken 30–60 minutes before the first meal of the day to be activated by the actively secreting proton pumps. Taking with food reduces effectiveness. They should not be crushed or chewed.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A nurse is administering IV phenytoin. Which action is most important?', '[{"id":"a","text":"Administer in dextrose solution at 100 mg/min"},{"id":"b","text":"Mix with normal saline and infuse no faster than 50 mg/min"},{"id":"c","text":"Give IV push undiluted over 2 minutes"},{"id":"d","text":"Administer intramuscularly for fastest absorption"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'IV phenytoin: use normal saline ONLY (precipitates in dextrose), infuse ≤50 mg/min (cardiac monitoring required — hypotension and dysrhythmias). IM administration is erratic and painful. Purple glove syndrome can occur at infusion sites.', '', '', '', 'published'),
  ('Pharmacology', 'sata', 'A patient started on amiodarone for atrial fibrillation needs teaching about adverse effects. Which should the nurse include? (Select all that apply)', '[{"id":"a","text":"Pulmonary toxicity — report new cough or dyspnea"},{"id":"b","text":"Photosensitivity — use sunscreen and cover skin"},{"id":"c","text":"Thyroid dysfunction — monitor TSH periodically"},{"id":"d","text":"Constipation is expected and no treatment is needed"},{"id":"e","text":"Corneal microdeposits — routine eye exams recommended"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'Amiodarone toxicities: pulmonary toxicity (most dangerous), photosensitivity (bluish discoloration), thyroid dysfunction (contains iodine), corneal deposits. It also causes hepatotoxicity. LFTs, TFTs, CXR, and eye exams are required for monitoring. Diarrhea (not constipation) can occur.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient with HIV is prescribed tenofovir/emtricitabine (Truvada). Which laboratory test requires monitoring?', '[{"id":"a","text":"Serum creatinine and GFR"},{"id":"b","text":"PT/INR"},{"id":"c","text":"Serum ammonia"},{"id":"d","text":"Serum calcium and phosphate"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Tenofovir (NRTI) is nephrotoxic — monitor kidney function (creatinine, GFR, urine protein) regularly. Tenofovir can cause Fanconi syndrome (proximal tubular injury). HIV medications also require CD4 count and viral load monitoring.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A nurse is about to give levothyroxine (Synthroid) 100 mcg PO. The patient just had breakfast. What should the nurse do?', '[{"id":"a","text":"Give the medication with food to prevent gastric upset"},{"id":"b","text":"Hold the medication and reschedule for 30–60 minutes before the next meal"},{"id":"c","text":"Administer at any time — timing doesn''t affect absorption"},{"id":"d","text":"Crush and mix with juice for easier administration"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Levothyroxine is best absorbed on an empty stomach, 30–60 minutes before breakfast. Food, calcium, iron, and antacids significantly reduce absorption. Always given at the same time each day. If the patient has eaten, give as soon as possible and separate from food by 30–60 minutes.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A nurse is caring for a patient receiving tissue plasminogen activator (tPA) for ischemic stroke. Which finding requires the nurse to stop the infusion immediately?', '[{"id":"a","text":"Blood pressure 148/90 mmHg"},{"id":"b","text":"New onset of severe headache, vomiting, and neurological deterioration"},{"id":"c","text":"Mild bruising at the IV site"},{"id":"d","text":"Improvement in facial droop after 30 minutes of infusion"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'During tPA infusion: severe headache + vomiting + neuro deterioration = hemorrhagic transformation (intracerebral bleeding) — STOP infusion immediately and notify provider. tPA carries a risk of potentially fatal intracranial hemorrhage. Mild bruising at IV site is expected. BP 148/90 requires monitoring but not stopping infusion.', '', '', '', 'published'),
  ('Pharmacology', 'sata', 'A nurse is reviewing medications for an elderly patient. Which medications increase fall risk and require extra caution? (Select all that apply)', '[{"id":"a","text":"Lorazepam (benzodiazepine)"},{"id":"b","text":"Metoprolol (beta-blocker)"},{"id":"c","text":"Lisinopril (ACE inhibitor)"},{"id":"d","text":"Diphenhydramine (antihistamine)"},{"id":"e","text":"Oxycodone (opioid)"}]'::jsonb, '{"ids":["a","b","c","d","e"]}'::jsonb, 'All five increase fall risk: benzodiazepines (sedation), beta-blockers (bradycardia, orthostatic hypotension), ACE inhibitors (orthostatic hypotension), diphenhydramine (anticholinergic confusion/sedation — Beers Criteria), and opioids (sedation, dizziness). High-risk fall precautions warranted.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient is prescribed sildenafil (Viagra) and asks if it interacts with any of their current medications. The nurse''s greatest concern would be if the patient is also taking:', '[{"id":"a","text":"Aspirin 81 mg daily"},{"id":"b","text":"Isosorbide mononitrate (nitrate)"},{"id":"c","text":"Metformin 500 mg twice daily"},{"id":"d","text":"Lisinopril 10 mg daily"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Sildenafil (PDE-5 inhibitor) + nitrates = CONTRAINDICATED — causes severe, potentially fatal hypotension. Both dilate blood vessels through different mechanisms with additive effect. This is an absolute contraindication. ACE inhibitors and metformin have no significant interaction.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with chronic obstructive pulmonary disease (COPD) is receiving supplemental oxygen. The nurse understands that oxygen should be titrated to maintain an SpO2 of:', '[{"id":"a","text":"98–100%"},{"id":"b","text":"94–98%"},{"id":"c","text":"88–92%"},{"id":"d","text":"82–85%"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'COPD patients retain CO2 and rely on hypoxic drive (low O2) to breathe. Target SpO2 88–92% — keeping it in this range avoids suppressing the respiratory drive. High-flow oxygen in COPD can cause CO2 retention and respiratory failure (the "COPD oxygen paradox").', '', '', '', 'published'),
  ('Medical-Surgical', 'sata', 'A patient is diagnosed with hypothyroidism. Which clinical findings does the nurse expect? (Select all that apply)', '[{"id":"a","text":"Weight gain despite decreased appetite"},{"id":"b","text":"Cold intolerance"},{"id":"c","text":"Constipation"},{"id":"d","text":"Tachycardia and heat intolerance"},{"id":"e","text":"Dry skin, hair loss, and fatigue"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'Hypothyroidism (low thyroid hormone) = slowed metabolism: weight gain, cold intolerance, constipation, dry skin, hair loss, fatigue, bradycardia, depression, myxedema. Tachycardia and heat intolerance are signs of HYPER-thyroidism (excessive thyroid hormone).', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient is admitted with a hemoglobin of 5.8 g/dL. The patient is symptomatic with dizziness and shortness of breath. What is the priority nursing intervention?', '[{"id":"a","text":"Administer oral iron supplementation"},{"id":"b","text":"Initiate a high-iron diet consultation"},{"id":"c","text":"Prepare for blood transfusion per order"},{"id":"d","text":"Obtain blood cultures before starting iron"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Hgb 5.8 with symptomatic anemia (dizziness, dyspnea) requires transfusion — oral iron takes weeks to raise hemoglobin and cannot correct acute symptomatic anemia. Normal Hgb: women 12–16 g/dL, men 14–18 g/dL. Transfusion is typically considered for symptomatic patients with Hgb <7–8 g/dL.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with rheumatoid arthritis reports morning stiffness lasting more than 2 hours. What is the most appropriate nursing advice?', '[{"id":"a","text":"Avoid activity until stiffness resolves to prevent joint damage"},{"id":"b","text":"Apply heat before activity and engage in gentle range-of-motion exercises"},{"id":"c","text":"Apply ice packs to all affected joints for 30 minutes"},{"id":"d","text":"Increase doses of ibuprofen to 800 mg every 4 hours"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'For RA morning stiffness: moist heat (warm shower, heating pad) reduces stiffness and increases joint mobility before activity. Gentle ROM exercises maintain function. Ice is used during acute inflammatory flares (swelling/heat). Avoid self-increasing NSAIDs without provider guidance.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient who had a cystectomy and ileal conduit asks the nurse what to expect from the stoma output. What is correct?', '[{"id":"a","text":"Stool-like output will be present for several days"},{"id":"b","text":"Urine drains continuously through the stoma — no ability to control output"},{"id":"c","text":"Output will be intermittent every 4–6 hours"},{"id":"d","text":"The stoma output will not have mucus"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'An ileal conduit (urinary diversion) drains urine continuously — there is no sphincter, so the patient cannot control output. A pouching system is worn at all times. Mucus is present in the urine (normal — from the bowel segment used). Stool is NOT present — the conduit carries urine only.', '', '', '', 'published'),
  ('Medical-Surgical', 'sata', 'A patient is diagnosed with neutropenia (ANC <500) after chemotherapy. Which findings require the nurse to notify the provider immediately? (Select all that apply)', '[{"id":"a","text":"Oral temperature of 38.3°C (100.9°F)"},{"id":"b","text":"Alopecia (hair loss)"},{"id":"c","text":"New chills without fever"},{"id":"d","text":"Redness and warmth at the IV site"},{"id":"e","text":"Mild nausea after chemotherapy"}]'::jsonb, '{"ids":["a","c","d"]}'::jsonb, 'In neutropenia: fever ≥38.3°C = febrile neutropenia (oncologic emergency — broad-spectrum antibiotics within 1 hour). Chills without fever can precede bacteremia. IV site infection in an immunocompromised patient is serious. Alopecia and mild nausea are expected chemo side effects.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A nurse is caring for a patient 4 hours post-nephrectomy. Which finding is most concerning?', '[{"id":"a","text":"Pain at incision site rated 6/10"},{"id":"b","text":"Urine output of 15 mL in the past hour"},{"id":"c","text":"Serosanguineous drainage on the dressing"},{"id":"d","text":"Temperature of 37.8°C"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Urine output 15 mL/hr is oliguria (<30 mL/hr) after nephrectomy — especially critical because the remaining kidney must now do 100% of filtration. This may indicate hemorrhage, shock, or acute kidney injury. Immediate provider notification is required.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient is admitted with Guillain-Barré syndrome. Which assessment is the highest priority?', '[{"id":"a","text":"Lower extremity motor strength and sensation"},{"id":"b","text":"Respiratory rate and tidal volume"},{"id":"c","text":"Cranial nerve function for facial weakness"},{"id":"d","text":"Deep tendon reflexes"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'GBS causes ascending paralysis that can progress to respiratory muscle failure — the primary cause of death. Monitor respiratory rate, tidal volume, vital capacity, and SpO2 frequently. Patients may require mechanical ventilation. Respiratory assessment is the priority life-threatening concern.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with a hip fracture is in Buck''s traction preoperatively. The purpose of this traction is:', '[{"id":"a","text":"To correct the bone fracture permanently"},{"id":"b","text":"To reduce muscle spasm and maintain alignment until surgery"},{"id":"c","text":"To increase blood supply to the fracture site"},{"id":"d","text":"To prevent deep vein thrombosis from immobility"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Buck''s traction (skin traction) is temporary, used preoperatively to reduce pain by decreasing muscle spasm and maintaining femoral alignment. It does NOT reduce or set the fracture — surgery does. Neurovascular checks, skin assessment, and comfort are key nursing priorities.', '', '', '', 'published'),
  ('Medical-Surgical', 'sata', 'A nurse is completing a post-operative assessment on a patient following abdominal surgery. Which findings indicate a return of bowel function? (Select all that apply)', '[{"id":"a","text":"Patient passes flatus"},{"id":"b","text":"Bowel sounds present in all four quadrants"},{"id":"c","text":"Patient has a bowel movement"},{"id":"d","text":"Abdomen is soft and non-distended"},{"id":"e","text":"Patient requests their first meal"}]'::jsonb, '{"ids":["a","b","c"]}'::jsonb, 'Return of bowel function after surgery: bowel sounds (peristalsis resuming), passing flatus, and bowel movement. Absence of distension and patient hunger are positive signs but not definitive indicators of bowel function. Advancing diet without bowel function risks ileus.', '', '', '', 'published'),
  ('Mental Health', 'mcq', 'A patient with obsessive-compulsive disorder (OCD) spends 3 hours per day washing their hands. The nurse''s initial therapeutic approach should be:', '[{"id":"a","text":"Prevent the patient from engaging in hand washing during therapy sessions"},{"id":"b","text":"Discuss the underlying anxiety driving the compulsion and set small limits over time"},{"id":"c","text":"Tell the patient the hand washing is unnecessary and irrational"},{"id":"d","text":"Encourage the patient to substitute a less harmful compulsion"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'For OCD, the nurse acknowledges the anxiety driving the compulsion and works collaboratively to gradually limit compulsive behaviors (exposure and response prevention is the gold standard). Abruptly preventing compulsions causes extreme anxiety and damages the therapeutic relationship. Never tell the patient their fears are irrational.', '', '', '', 'published'),
  ('Mental Health', 'mcq', 'A patient is admitted voluntarily for depression. They now want to leave against medical advice. The nurse understands that:', '[{"id":"a","text":"Voluntary patients can be held involuntarily if they pose a danger to themselves"},{"id":"b","text":"Voluntary patients have the absolute right to leave at any time"},{"id":"c","text":"The patient must be physically restrained until a psychiatrist arrives"},{"id":"d","text":"The patient cannot leave until 72 hours of treatment are complete"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Voluntary patients generally have the right to leave. However, if the patient is assessed as a danger to self or others, the nurse can initiate the process for involuntary detention (5150/hold) while arranging psychiatric evaluation. This overrides the right to leave.', '', '', '', 'published'),
  ('Mental Health', 'sata', 'A nurse is caring for a patient with borderline personality disorder. Which behaviors does the nurse expect? (Select all that apply)', '[{"id":"a","text":"Unstable intense relationships — idealization followed by devaluation"},{"id":"b","text":"Self-mutilation or suicidal gestures"},{"id":"c","text":"Auditory hallucinations telling the patient to harm others"},{"id":"d","text":"Intense fear of abandonment"},{"id":"e","text":"Impulsive behaviors (spending, substance use, self-harm)"}]'::jsonb, '{"ids":["a","b","d","e"]}'::jsonb, 'BPD hallmarks: splitting (idealize/devalue), fear of abandonment, identity disturbance, impulsivity, self-harm, emotional dysregulation. Auditory command hallucinations are characteristic of psychotic disorders (schizophrenia), not BPD. Set consistent limits and use dialectical behavior therapy (DBT) approach.', '', '', '', 'published'),
  ('Mental Health', 'mcq', 'A patient is brought to the ER agitated, diaphoretic, with a temperature of 40.2°C, HR 128, clonus, and has taken an antidepressant overdose in combination with tramadol. The nurse suspects:', '[{"id":"a","text":"Neuroleptic malignant syndrome"},{"id":"b","text":"Serotonin syndrome"},{"id":"c","text":"Anticholinergic toxidrome"},{"id":"d","text":"Opioid toxicity"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Serotonin syndrome triad: altered mental status + autonomic instability (tachycardia, hyperthermia, diaphoresis) + neuromuscular abnormalities (clonus, hyperreflexia, tremor). Caused by serotonergic drug combinations (SSRI + tramadol, linezolid, etc.). NMS also causes hyperthermia but has "lead-pipe" rigidity and bradykinesia, not clonus.', '', '', '', 'published'),
  ('Mental Health', 'mcq', 'A nurse is using motivational interviewing with a patient who is ambivalent about quitting smoking. Which response best demonstrates this technique?', '[{"id":"a","text":"\"Smoking causes lung cancer. You really should quit for your health.\""},{"id":"b","text":"\"What concerns you most about your smoking right now?\""},{"id":"c","text":"\"Have you tried nicotine patches? Many patients find them helpful.\""},{"id":"d","text":"\"On a scale of 1–10, how ready are you to quit smoking today?\""}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Motivational interviewing (MI) uses open-ended questions to explore the patient''s own concerns and motivations (elicit-provide-elicit). Option B evokes the patient''s perspective. Option D uses a readiness ruler (also MI), but B is more open-ended and exploratory. Direct advice ("you should quit") is confrontational and reduces autonomy.', '', '', '', 'published'),
  ('Maternal and Newborn', 'mcq', 'A nurse is assessing a patient at 10 weeks gestation. Fundal height measurement is appropriate starting at which gestational age?', '[{"id":"a","text":"10 weeks"},{"id":"b","text":"20 weeks"},{"id":"c","text":"28 weeks"},{"id":"d","text":"32 weeks"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Fundal height (McDonald''s rule) measurement begins at 20 weeks gestation. After 20 weeks, fundal height in centimeters approximates gestational age in weeks (±2 cm). Before 20 weeks, the uterus is too small to measure reliably via tape measure from symphysis pubis to fundus.', '', '', '', 'published'),
  ('Maternal and Newborn', 'mcq', 'A nurse is caring for a patient in the second stage of labor. The patient is pushing effectively. Which fetal heart rate finding requires immediate action?', '[{"id":"a","text":"FHR 145 bpm between contractions"},{"id":"b","text":"Accelerations with fetal movement"},{"id":"c","text":"Prolonged deceleration to 80 bpm for 3 minutes"},{"id":"d","text":"Variable decelerations with rapid recovery to baseline"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'A prolonged deceleration (>2 min, <10 min) to 80 bpm for 3 minutes indicates significant fetal compromise. Interventions: stop pushing, reposition, O2 by mask, IV bolus, notify provider — possible emergency delivery. Accelerations are reassuring. Brief variable decelerations with quick recovery are common in second stage.', '', '', '', 'published'),
  ('Maternal and Newborn', 'sata', 'A nurse is caring for a patient with gestational diabetes. Which teaching points are correct? (Select all that apply)', '[{"id":"a","text":"Monitor blood glucose before meals and at bedtime"},{"id":"b","text":"Gestational diabetes resolves immediately after delivery in all cases"},{"id":"c","text":"The newborn is at risk for hypoglycemia after birth"},{"id":"d","text":"Dietary modifications are the first-line management"},{"id":"e","text":"A postpartum glucose tolerance test is recommended at 6–12 weeks"}]'::jsonb, '{"ids":["a","c","d","e"]}'::jsonb, 'GDM teaching: monitor glucose regularly, diet/exercise first-line, newborn monitored for hypoglycemia (fetal hyperinsulinism), and postpartum GTT at 6–12 weeks (GDM increases lifetime risk of type 2 diabetes — does NOT always resolve; 50% develop T2DM within 10 years).', '', '', '', 'published'),
  ('Maternal and Newborn', 'mcq', 'A newborn has a positive Ortolani and Barlow test. What does this indicate?', '[{"id":"a","text":"Normal hip development"},{"id":"b","text":"Developmental dysplasia of the hip (DDH)"},{"id":"c","text":"Talipes equinovarus (clubfoot)"},{"id":"d","text":"Cerebral palsy"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Ortolani (reduction "clunk") and Barlow (dislocation with pressure) tests assess for hip instability/DDH. A positive finding requires urgent orthopedic referral. DDH is more common in females, first-born, breech presentation. Treatment: Pavlik harness if diagnosed early.', '', '', '', 'published'),
  ('Maternal and Newborn', 'mcq', 'A nurse is caring for a patient who delivered 30 minutes ago and lost an estimated 600 mL of blood. Vital signs are stable. What is the correct classification of this blood loss?', '[{"id":"a","text":"Normal blood loss for vaginal delivery"},{"id":"b","text":"Primary postpartum hemorrhage — requires immediate intervention"},{"id":"c","text":"Secondary postpartum hemorrhage"},{"id":"d","text":"Expected blood loss for a cesarean section"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Primary PPH: ≥500 mL blood loss within 24 hours of vaginal delivery (≥1000 mL for cesarean). 600 mL qualifies as primary PPH. Assess the "4 T''s": Tone (atony), Tissue (retained placenta), Trauma (lacerations), Thrombin (coagulopathy). Most common cause is uterine atony.', '', '', '', 'published'),
  ('Pediatrics', 'mcq', 'A 5-year-old with acute lymphocytic leukemia (ALL) has a platelet count of 18,000/mm³. Which activity should the nurse avoid?', '[{"id":"a","text":"Reading books quietly in bed"},{"id":"b","text":"Taking an oral temperature"},{"id":"c","text":"Administering rectal suppositories"},{"id":"d","text":"Age-appropriate play therapy"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'With thrombocytopenia (platelets <20,000), avoid any invasive rectal procedures — suppositories, enemas, rectal temperatures — due to severe bleeding risk. Also avoid IM injections, aspirin, flossing, contact sports. Use only oral or axillary temperatures.', '', '', '', 'published'),
  ('Pediatrics', 'mcq', 'A nurse is caring for a child with epiglottitis. Which action is the priority?', '[{"id":"a","text":"Examine the throat using a tongue depressor to assess swelling"},{"id":"b","text":"Keep the child calm and allow the parent to hold the child in a comfortable position"},{"id":"c","text":"Administer nebulized racemic epinephrine immediately"},{"id":"d","text":"Place a nasogastric tube for medication administration"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Epiglottitis is a life-threatening emergency. NEVER examine the throat or use a tongue depressor — this can cause complete airway obstruction by triggering laryngospasm. Keep the child calm (crying worsens obstruction). Allow parent holding, minimize invasive procedures. Airway equipment and anesthesia should be immediately available.', '', '', '', 'published'),
  ('Pediatrics', 'sata', 'A child with nephrotic syndrome is admitted. Which findings does the nurse expect? (Select all that apply)', '[{"id":"a","text":"Massive proteinuria (frothy urine)"},{"id":"b","text":"Periorbital and generalized edema"},{"id":"c","text":"Hypoalbuminemia"},{"id":"d","text":"Hematuria and hypertension"},{"id":"e","text":"Hyperlipidemia and lipiduria"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'Nephrotic syndrome: massive proteinuria (>3.5g/day → frothy urine), hypoalbuminemia (protein lost), edema (low oncotic pressure), hyperlipidemia (liver compensates by making lipids). Hematuria and hypertension are hallmarks of NEPHRITIC syndrome, not nephrotic.', '', '', '', 'published'),
  ('Pediatrics', 'mcq', 'A 3-year-old ingests an unknown household chemical. What is the nurse''s initial action?', '[{"id":"a","text":"Induce vomiting with syrup of ipecac"},{"id":"b","text":"Call Poison Control (1-800-222-1222) immediately"},{"id":"c","text":"Give the child milk to dilute the chemical"},{"id":"d","text":"Administer activated charcoal at home before arriving at the hospital"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Call Poison Control immediately — they provide specific guidance based on the substance. Ipecac is NO LONGER recommended (risk of aspiration, delayed decontamination). Do not give milk (may enhance absorption of some substances). Activated charcoal requires medical supervision.', '', '', '', 'published'),
  ('Pediatrics', 'mcq', 'A nurse is assessing a 6-week-old infant who is vomiting forcefully after every feeding. The vomit is non-bilious and projectile. The nurse palpates an olive-shaped mass in the epigastric area. What condition does the nurse suspect?', '[{"id":"a","text":"Intussusception"},{"id":"b","text":"Hirschsprung''s disease"},{"id":"c","text":"Pyloric stenosis"},{"id":"d","text":"Gastroesophageal reflux"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Pyloric stenosis: 2–6 week old infant, projectile non-bilious vomiting after feeding, palpable "olive" mass in right epigastrium, hungry after vomiting. Leads to metabolic alkalosis with hypokalemia. Treatment: surgical pyloromyotomy. Intussusception: "currant jelly" stool, colicky pain, sausage-shaped mass.', '', '', '', 'published'),
  ('Safety and Infection Control', 'mcq', 'A nurse is doing medication reconciliation on admission. Which is the most complete and accurate source for obtaining the medication history?', '[{"id":"a","text":"The patient''s family member"},{"id":"b","text":"The emergency department physician''s notes"},{"id":"c","text":"A brown bag review of all medications the patient brings from home"},{"id":"d","text":"The patient''s pharmacy records only"}]'::jsonb, '{"ids":["c"]}'::jsonb, '"Brown bag" medication review (patient brings all medications) is the most complete source — includes prescriptions, OTCs, supplements, and herbals that patients often omit when asked verbally. Discrepancies trigger clarification. Pharmacy records miss PRN and recently changed medications.', '', '', '', 'published'),
  ('Safety and Infection Control', 'sata', 'A nurse is performing the "five rights" of medication administration. What are they? (Select all that apply)', '[{"id":"a","text":"Right patient"},{"id":"b","text":"Right medication"},{"id":"c","text":"Right dose"},{"id":"d","text":"Right route"},{"id":"e","text":"Right time"}]'::jsonb, '{"ids":["a","b","c","d","e"]}'::jsonb, 'The Five Rights: right patient (2 identifiers), right drug, right dose, right route, right time. Extended rights include: right documentation, right reason, and right response. Using 2 patient identifiers (name + DOB or MRN) prevents wrong-patient errors — the most preventable medication error.', '', '', '', 'published'),
  ('Safety and Infection Control', 'mcq', 'Which hand hygiene method is most effective against Clostridium difficile spores?', '[{"id":"a","text":"Alcohol-based hand rub for 20 seconds"},{"id":"b","text":"Soap and water for at least 20 seconds"},{"id":"c","text":"Antiseptic wipes"},{"id":"d","text":"Either method is equally effective"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'C. diff produces spores that are NOT killed by alcohol-based hand sanitizers. Soap and water (physical scrubbing for ≥20 seconds) is required to mechanically remove spores. This is one of the key reasons for special precautions: hand washing, not just sanitizer, when caring for C. diff patients.', '', '', '', 'published'),
  ('Safety and Infection Control', 'mcq', 'A nurse is caring for a patient with varicella (chickenpox). Which type of isolation is required?', '[{"id":"a","text":"Contact precautions only"},{"id":"b","text":"Droplet precautions only"},{"id":"c","text":"Airborne AND contact precautions"},{"id":"d","text":"Standard precautions only"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Varicella (chickenpox) requires BOTH airborne precautions (negative pressure room, N95) AND contact precautions (gown and gloves) because it spreads via airborne droplet nuclei AND direct contact with vesicle fluid. Shingles (herpes zoster) is contact only unless disseminated.', '', '', '', 'published'),
  ('Safety and Infection Control', 'mcq', 'A nurse is restraining a patient for the first time due to combative behavior. Which action must the nurse take?', '[{"id":"a","text":"Apply wrist restraints and check every 2 hours"},{"id":"b","text":"Obtain a provider order, document behavior justifying restraint, and reassess every 2 hours"},{"id":"c","text":"Obtain consent from the patient before applying restraints"},{"id":"d","text":"Use a jacket restraint for maximum security"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Restraint requirements: provider order (must be time-limited), document the behavior and all alternatives tried, reassess every 2 hours (circulation, sensation, range of motion), offer alternatives (reduce stimulation, redirect, toileting). Least restrictive method first. Jacket/vest restraints increase asphyxiation risk.', '', '', '', 'published'),
  ('Leadership and Management', 'mcq', 'A nurse witnesses a colleague charting a blood pressure that was never taken. The nurse''s legal and ethical obligation is to:', '[{"id":"a","text":"Confront the colleague privately and ask them to correct the chart"},{"id":"b","text":"Report the incident through the facility''s chain of command"},{"id":"c","text":"Document the observation in the patient''s chart"},{"id":"d","text":"Ignore it — it is not the nurse''s responsibility"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Falsifying medical records is fraud and a criminal offense. The nurse has an ethical and legal obligation to report through proper channels (charge nurse, supervisor, risk management). This protects patient safety and maintains professional standards. Ignoring it makes the witness complicit. Documenting in the patient''s chart is inappropriate.', '', '', '', 'published'),
  ('Leadership and Management', 'mcq', 'A nurse is caring for a patient who is Jehovah''s Witness and refuses a blood transfusion despite critical anemia. The nurse understands that:', '[{"id":"a","text":"The family can override the patient''s decision if the patient is in danger"},{"id":"b","text":"The hospital has the right to get a court order if the patient is a danger to themselves"},{"id":"c","text":"A competent adult patient has the right to refuse treatment, including life-saving blood transfusions"},{"id":"d","text":"The nurse should administer the transfusion while the patient is asleep to save their life"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Informed refusal: a competent adult has the absolute right to refuse any treatment, including life-saving interventions, based on religious or personal beliefs. Administering blood without consent is assault/battery. The nurse ensures the patient understands the consequences, documents informed refusal, and notifies the provider. Family cannot override a competent adult.', '', '', '', 'published'),
  ('Leadership and Management', 'sata', 'A nurse is caring for 5 patients. Which tasks can be safely delegated to a licensed practical nurse (LPN/LVN)? (Select all that apply)', '[{"id":"a","text":"Administering a scheduled oral medication to a stable patient"},{"id":"b","text":"Performing the initial nursing assessment on a newly admitted patient"},{"id":"c","text":"Changing a wound dressing on a chronic, stable wound"},{"id":"d","text":"Teaching a patient about a new insulin injection technique"},{"id":"e","text":"Administering an IV push medication on a stable patient (per state law and facility policy)"}]'::jsonb, '{"ids":["a","c","e"]}'::jsonb, 'LPNs/LVNs: can administer scheduled medications to stable patients, change dressings, collect specimens, monitor IV infusions (facility specific). Cannot: perform initial admission assessments (RN-only scope), develop care plans, or perform patient teaching independently (they reinforce RN teaching). IV push depends on state law.', '', '', '', 'published'),
  ('Leadership and Management', 'mcq', 'A patient care situation deteriorates rapidly. Which communication tool provides the most structured and efficient handoff?', '[{"id":"a","text":"SBAR"},{"id":"b","text":"Narrative nursing note"},{"id":"c","text":"Shift end-of-shift report"},{"id":"d","text":"Informal verbal update"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'SBAR (Situation-Background-Assessment-Recommendation) provides a standardized, concise communication format for urgent clinical situations. Studies show SBAR reduces communication errors, improves response time, and creates a common language between nurses and physicians during handoffs and emergencies.', '', '', '', 'published'),
  ('Leadership and Management', 'mcq', 'A nurse is using the "I PASS the BATON" handoff tool. What does the "A" stand for?', '[{"id":"a","text":"Allergies"},{"id":"b","text":"Assessment and actions taken"},{"id":"c","text":"Anticipated orders"},{"id":"d","text":"Admission diagnosis"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'I PASS the BATON: Introduction, Patient, Assessment, Situation, Safety (allergies, alerts) — the BATON portion: Background, Actions, Timing, Ownership, Next. "A" = Allergies and alerts (code status, fall risk, isolation). This Joint Commission-endorsed tool standardizes handoffs to prevent information loss.', '', '', '', 'published'),
  ('NGN Case Studies', 'sata', 'A 72-year-old with COPD, heart failure, and type 2 diabetes is admitted with worsening dyspnea. SpO2 82%, RR 28, HR 112, BP 158/96, bilateral crackles, 3+ pitting edema. Which nursing actions are priority? (Select all that apply)', '[{"id":"a","text":"Position in high Fowler''s to ease breathing"},{"id":"b","text":"Apply oxygen at 2 L/min via nasal cannula targeting SpO2 88–92%"},{"id":"c","text":"Administer furosemide IV as ordered for fluid overload"},{"id":"d","text":"Apply 100% non-rebreather mask at 15 L/min"},{"id":"e","text":"Notify provider and prepare for possible BiPAP"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'COPD + HF: HOB elevation (reduce preload, improve lung expansion), low-flow O2 targeting 88–92% (COPD hypoxic drive), IV diuresis for fluid overload (bilateral crackles, 3+ edema), and provider notification for escalation including BiPAP. High-flow 100% O2 (non-rebreather) risks respiratory failure in COPD by eliminating hypoxic drive.', '', '', '', 'published'),
  ('NGN Case Studies', 'mcq', 'A nurse is caring for a patient 2 days post-ischemic stroke. The patient has left-sided weakness and dysphagia. The patient is hungry and wants to eat. What is the priority nursing action?', '[{"id":"a","text":"Provide a regular diet with thin liquids as ordered"},{"id":"b","text":"Complete a swallowing screen before any oral intake"},{"id":"c","text":"Give the patient soft foods and encourage self-feeding with the right hand"},{"id":"d","text":"Insert an NG tube for enteral feeding immediately"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Dysphagia after stroke significantly increases aspiration pneumonia risk (leading preventable complication). Conduct a bedside swallowing screen (e.g., 3-oz water test) before any oral intake. Refer to speech-language pathology for formal evaluation. Do not feed orally without swallow screen clearance.', '', '', '', 'published'),
  ('NGN Case Studies', 'sata', 'A nurse reviews labs for a patient with chronic liver failure: Na 128, K 5.8, Creatinine 3.2, ammonia 98, INR 3.1, albumin 1.8, bilirubin 8.4. Which conditions do these values indicate? (Select all that apply)', '[{"id":"a","text":"Hyponatremia"},{"id":"b","text":"Hepatic encephalopathy risk"},{"id":"c","text":"Impaired coagulation"},{"id":"d","text":"Hyperkalemia requiring immediate intervention"},{"id":"e","text":"Acute kidney injury"}]'::jsonb, '{"ids":["a","b","c","d","e"]}'::jsonb, 'All values are abnormal: Na 128 = hyponatremia (dilutional), K 5.8 = hyperkalemia (cardiac risk — K >6 requires immediate treatment), creatinine 3.2 = AKI (hepatorenal syndrome), ammonia 98 = encephalopathy risk, INR 3.1 = coagulopathy, albumin 1.8 = severe malnutrition and edema risk, bilirubin 8.4 = cholestasis/hepatocellular failure.', '', '', '', 'published'),
  ('NGN Case Studies', 'mcq', 'A 45-year-old male with no PMH presents with 2 hours of crushing substernal chest pain radiating to the left jaw and arm, diaphoresis, and nausea. 12-lead ECG shows ST elevation in leads II, III, and aVF. This pattern indicates:', '[{"id":"a","text":"Anterior STEMI — left anterior descending artery occlusion"},{"id":"b","text":"Inferior STEMI — right coronary artery occlusion"},{"id":"c","text":"Lateral STEMI — circumflex artery occlusion"},{"id":"d","text":"Unstable angina — admit for monitoring"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Inferior STEMI: ST elevation in leads II, III, aVF → right coronary artery territory. Anterior STEMI = V1–V4 (LAD). Lateral STEMI = I, aVL, V5–V6 (circumflex). This patient needs immediate activation of the cath lab (door-to-balloon <90 min). Also assess for RV involvement (right-sided ECG leads).', '', '', '', 'published'),
  ('NGN Case Studies', 'sata', 'A nurse receives a patient in anaphylaxis after a bee sting. Which interventions are performed simultaneously? (Select all that apply)', '[{"id":"a","text":"Administer epinephrine 0.3 mg IM to the outer thigh"},{"id":"b","text":"Apply oxygen via non-rebreather mask"},{"id":"c","text":"Establish large-bore IV access and begin IV fluids"},{"id":"d","text":"Administer IV diphenhydramine as definitive treatment"},{"id":"e","text":"Place patient supine with legs elevated (unless dyspneic)"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'Anaphylaxis: epinephrine IM (lateral thigh) is first-line — do not delay. Simultaneously: high-flow O2, IV access + fluids for hypotension, supine with legs elevated to increase venous return (sit up if airway compromised). Diphenhydramine and corticosteroids are ADJUNCTS, not first-line — they are too slow to prevent laryngeal edema.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient with type 2 diabetes is started on insulin glargine (Lantus). Which statement indicates the patient needs additional teaching?', '[{"id":"a","text":"\"I will give this injection at the same time each day.\""},{"id":"b","text":"\"I should not mix this insulin with other insulins in the same syringe.\""},{"id":"c","text":"\"I can use this insulin for hypoglycemic episodes because it works quickly.\""},{"id":"d","text":"\"I should rotate injection sites to prevent lipodystrophy.\""}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Insulin glargine (Lantus) is a long-acting basal insulin with no peak — it cannot treat acute hypoglycemia. Short-acting (regular) or rapid-acting (lispro, aspart) insulin is used for hyperglycemia correction. Glargine should NOT be mixed with other insulins (pH incompatibility).', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient is receiving gentamicin. Which pair of assessments is most critical to monitor for drug toxicity?', '[{"id":"a","text":"Blood pressure and heart rate"},{"id":"b","text":"Hearing and kidney function"},{"id":"c","text":"Liver function tests and bilirubin"},{"id":"d","text":"Blood glucose and HbA1c"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Aminoglycosides (gentamicin, tobramycin, amikacin) are ototoxic (irreversible hearing loss, tinnitus, vestibular damage) and nephrotoxic. Monitor: peak and trough drug levels, BUN/creatinine, urine output, and audiometric testing. Keep trough levels low to minimize toxicity.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient taking prednisone long-term for Crohn''s disease asks why they need to increase the dose during a surgery. The nurse explains:', '[{"id":"a","text":"Surgery requires stronger anti-inflammatory coverage"},{"id":"b","text":"Long-term steroids suppress the adrenal glands — \"stress dosing\" prevents adrenal crisis"},{"id":"c","text":"Prednisone prevents surgical site infections"},{"id":"d","text":"Higher doses reduce post-operative nausea"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Chronic exogenous corticosteroids suppress the HPA axis — the adrenal glands atrophy and cannot mount a cortisol stress response. "Stress dosing" (increasing steroid dose perioperatively) prevents adrenal insufficiency/Addisonian crisis during the physical stress of surgery. Abrupt steroid withdrawal is dangerous.', '', '', '', 'published'),
  ('Pharmacology', 'sata', 'A nurse is reviewing contraindications for NSAIDs. Which conditions should alert the nurse to question the order? (Select all that apply)', '[{"id":"a","text":"Active peptic ulcer disease"},{"id":"b","text":"Chronic kidney disease stage 4"},{"id":"c","text":"Hypertension controlled with lisinopril"},{"id":"d","text":"History of asthma"},{"id":"e","text":"Type 2 diabetes on oral agents"}]'::jsonb, '{"ids":["a","b","c","d"]}'::jsonb, 'NSAID cautions/contraindications: GI ulcers (NSAIDs inhibit prostaglandins protecting gastric mucosa), CKD (NSAIDs reduce renal prostaglandins and GFR), HTN with ACE inhibitors (dangerous hyperkalemia, reduced antihypertensive effect), aspirin-sensitive asthma (Samter''s triad — bronchospasm). Diabetes alone is not a contraindication.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient is prescribed ciprofloxacin for a UTI. Which instruction is most important?', '[{"id":"a","text":"Take with milk to reduce stomach upset"},{"id":"b","text":"Avoid sun exposure and use sunscreen"},{"id":"c","text":"Take with antacids to improve absorption"},{"id":"d","text":"Limit water intake to 1 L/day"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Fluoroquinolones (ciprofloxacin, levofloxacin) cause photosensitivity — sunscreen and sun-protective clothing are essential. Do NOT take with antacids, calcium, iron, or dairy (chelation reduces absorption by up to 90%). Increase fluid intake (2–3 L/day) to prevent crystalluria.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with sickle cell disease is admitted during a vaso-occlusive crisis. Which interventions are the highest priority? (Select all that apply)', '[{"id":"a","text":"Aggressive IV hydration"},{"id":"b","text":"Opioid analgesia for pain management"},{"id":"c","text":"Supplemental oxygen"},{"id":"d","text":"Incentive spirometry"},{"id":"e","text":"Encourage outdoor activity"}]'::jsonb, '{"ids":["a","b","c","d"]}'::jsonb, 'Sickle cell crisis management: IV fluids (dilute sickled cells, restore circulation), opioid analgesia (severe pain), supplemental O2 (prevent further sickling), incentive spirometry (prevent acute chest syndrome). Avoid cold, stress, dehydration, and high-altitude activity — all trigger sickling.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with peripheral arterial disease (PAD) asks how to care for their feet. Which instruction is correct?', '[{"id":"a","text":"Soak feet in hot water daily to improve circulation"},{"id":"b","text":"Walk barefoot at home to toughen the skin"},{"id":"c","text":"Wear well-fitting shoes, inspect feet daily, and avoid crossing legs"},{"id":"d","text":"Apply heating pads to legs to relieve pain"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'PAD foot care: daily inspection (impaired sensation masks injury), well-fitting shoes (prevent trauma), avoid crossing legs (further reduces blood flow), avoid extremes of temperature (decreased sensation → burns/frostbite). Heating pads and hot soaks can cause burns in patients with decreased sensation.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient newly diagnosed with multiple sclerosis asks about the disease. Which explanation is most accurate?', '[{"id":"a","text":"MS is caused by a bacterial infection and is curable with antibiotics"},{"id":"b","text":"MS involves demyelination of axons in the CNS, causing varied neurological symptoms"},{"id":"c","text":"MS primarily affects the peripheral nervous system and muscles"},{"id":"d","text":"MS consistently progresses in all patients and always leads to complete disability"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'MS is an autoimmune disease causing demyelination of CNS axons, disrupting nerve signal transmission. Symptoms vary based on lesion location: optic neuritis, weakness, spasticity, bladder dysfunction, fatigue. MS course is variable — many patients maintain function for years with disease-modifying therapies.', '', '', '', 'published'),
  ('Medical-Surgical', 'sata', 'A patient is being discharged after coronary artery bypass graft (CABG) surgery. Which discharge teaching points are essential? (Select all that apply)', '[{"id":"a","text":"No lifting >5–10 lbs until sternal healing is complete (6–8 weeks)"},{"id":"b","text":"Avoid driving until approved by surgeon (typically 4–6 weeks)"},{"id":"c","text":"Take aspirin and prescribed medications as directed"},{"id":"d","text":"Resume all normal activities within 2 weeks"},{"id":"e","text":"Report fever >38°C, increased wound drainage, or new chest pain"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'CABG discharge: sternum heals in 6–8 weeks (no heavy lifting, sternal precautions), driving restriction (reaction time, sternal stress), antiplatelet therapy compliance critical for graft patency, warning signs of infection/rejection. Full activity resumption takes weeks to months — not 2 weeks.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient develops a fever of 39.2°C on postoperative day 1. What is the most likely cause?', '[{"id":"a","text":"Wound infection"},{"id":"b","text":"Pneumonia"},{"id":"c","text":"Atelectasis"},{"id":"d","text":"Deep vein thrombosis"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'The "5 W''s" of post-op fever by day: Wind (day 1–2 = atelectasis), Water (day 3 = UTI), Wound (day 5–7 = infection), Walking (day 5+ = DVT), Wonder drugs (any day = drug fever). Day 1 fever is almost always atelectasis — encourage deep breathing and incentive spirometry.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient is receiving total parenteral nutrition (TPN). Which electrolyte is at the greatest risk for refeeding syndrome when restarting nutrition?', '[{"id":"a","text":"Sodium"},{"id":"b","text":"Phosphorus"},{"id":"c","text":"Calcium"},{"id":"d","text":"Chloride"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Refeeding syndrome: after starvation, reintroducing carbohydrates triggers insulin release → cells take up phosphate, potassium, and magnesium from blood → severe hypophosphatemia. Phosphorus is the key electrolyte to monitor. Hypophosphatemia causes respiratory failure, cardiac arrest, and seizures.', '', '', '', 'published'),
  ('Mental Health', 'mcq', 'A patient with major depressive disorder asks, "What is the point of going on?" How should the nurse respond?', '[{"id":"a","text":"\"You have so much to live for. Think about your family.\""},{"id":"b","text":"\"It sounds like you''re really struggling. Are you thinking about harming yourself?\""},{"id":"c","text":"\"The antidepressants will kick in soon and you''ll feel better.\""},{"id":"d","text":"\"Let me call your doctor so they can adjust your medication.\""}]'::jsonb, '{"ids":["b"]}'::jsonb, 'A statement like "what''s the point of going on?" requires a direct, empathic response and immediate safety assessment. Asking directly about suicidal ideation is therapeutic — it does not plant the idea. Minimizing feelings or deflecting to medication change avoids the safety assessment, which is the priority.', '', '', '', 'published'),
  ('Maternal and Newborn', 'mcq', 'A nurse is caring for a woman at 16 weeks gestation who has just been told her fetus has Down syndrome (trisomy 21) confirmed by amniocentesis. The patient is crying. The nurse''s priority response is:', '[{"id":"a","text":"Provide information about Down syndrome resources and support groups"},{"id":"b","text":"Explain all options including termination of the pregnancy"},{"id":"c","text":"Sit with the patient, offer presence, and provide emotional support"},{"id":"d","text":"Assure the patient that children with Down syndrome live fulfilling lives"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'In crisis and acute grief, the therapeutic priority is emotional presence and support — not information, reassurance, or option review. The patient cannot process information while acutely distressed. Sit quietly, offer tissues, use therapeutic silence. Information and options come later when the patient is ready.', '', '', '', 'published'),
  ('Pediatrics', 'mcq', 'A 10-month-old is receiving oral rehydration therapy for diarrhea. The parent asks when to call the doctor. What is the most important warning sign to report?', '[{"id":"a","text":"One or two loose stools"},{"id":"b","text":"No wet diapers in 8 hours and sunken fontanelle"},{"id":"c","text":"Mild fussiness"},{"id":"d","text":"Decreased appetite for solid foods"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Signs of severe dehydration in an infant: no wet diapers >8 hours (oliguria), sunken fontanelle, sunken eyes, dry mucous membranes, absent tears, skin tenting, lethargy. These require immediate medical evaluation. Mild symptoms (loose stool, fussiness, decreased appetite) are expected and manageable at home with ORT.', '', '', '', 'published'),
  ('Safety and Infection Control', 'mcq', 'A nurse is preparing to remove a patient from contact isolation. Which is the correct order for doffing PPE?', '[{"id":"a","text":"Mask → gown → gloves → hand hygiene"},{"id":"b","text":"Gloves → hand hygiene → gown → hand hygiene → mask → hand hygiene"},{"id":"c","text":"Gown → gloves → mask → hand hygiene"},{"id":"d","text":"All PPE can be removed in any order as long as hand hygiene is performed last"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Correct doffing (removal) sequence: gloves (most contaminated) → hand hygiene → gown → hand hygiene → mask/respirator (if worn) → hand hygiene. Always perform hand hygiene after each step. The order is designed to prevent self-contamination from the most to least contaminated items.', '', '', '', 'published'),
  ('Leadership and Management', 'mcq', 'A nurse learns that a co-worker is consistently coming to work smelling of alcohol. What is the most appropriate first action?', '[{"id":"a","text":"Ignore it — the co-worker''s personal life is their own business"},{"id":"b","text":"Cover for the co-worker to protect their license"},{"id":"c","text":"Report the concern to the charge nurse or supervisor immediately"},{"id":"d","text":"Confront the co-worker privately and threaten to report them"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'A nurse impaired by alcohol on duty is an immediate patient safety threat. Report to the supervisor or charge nurse immediately. This is a professional and ethical obligation. Most state nursing boards have confidential peer assistance programs for nurses with substance use disorders. Covering for the nurse is enabling behavior that endangers patients.', '', '', '', 'published'),
  ('NGN Case Studies', 'mcq', 'A 58-year-old is admitted following a fall. CT scan shows a subdural hematoma. The patient was alert on arrival but is now difficult to arouse, with unequal pupils and declining GCS. What is the priority intervention?', '[{"id":"a","text":"Reposition the patient and reassess in 30 minutes"},{"id":"b","text":"Activate a rapid response/code and prepare for emergent neurosurgical intervention"},{"id":"c","text":"Administer IV morphine for pain and recheck pupils"},{"id":"d","text":"Perform a 12-lead ECG to rule out cardiac cause"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'A patient deteriorating from alert to unarousable with unequal pupils and declining GCS is exhibiting signs of transtentorial herniation — a neurosurgical emergency. Immediate: call rapid response/neurosurgery, elevate HOB 30°, administer osmotic therapy (mannitol or hypertonic saline) if ordered, prepare for emergency craniotomy.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient receives an overdose of acetaminophen 8 hours ago and denies symptoms. Which laboratory value is most important to monitor?', '[{"id":"a","text":"Serum creatinine"},{"id":"b","text":"Serum acetaminophen level and liver function tests"},{"id":"c","text":"CBC and platelet count"},{"id":"d","text":"Serum glucose"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Acetaminophen overdose causes hepatotoxicity that peaks at 72–96 hours — the patient is asymptomatic early. Monitor: acetaminophen level (Rumack-Matthew nomogram determines N-acetylcysteine [NAC] need), and AST/ALT every 24 hours. NAC is most effective when given <8–10 hours post-ingestion but can still help later.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with benign prostatic hyperplasia (BPH) is in acute urinary retention. Which is the first intervention?', '[{"id":"a","text":"Encourage the patient to drink 3 L of fluid to stimulate voiding"},{"id":"b","text":"Apply a warm compress to the suprapubic area and attempt voiding"},{"id":"c","text":"Insert a urinary catheter to relieve bladder distension"},{"id":"d","text":"Administer an alpha-blocker and wait 2 hours"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Acute urinary retention with a distended, painful bladder requires immediate catheterization to relieve obstruction and prevent bladder/kidney damage. Up to 1,000 mL may be drained initially (some facilities drain 500 mL, clamp, then continue to prevent hypotension from rapid decompression). Warm compresses and fluids are NOT sufficient for acute retention.', '', '', '', 'published'),
  ('Mental Health', 'mcq', 'A patient with schizophrenia is experiencing command hallucinations telling them to hurt a named co-worker. What is the nurse''s legal and ethical obligation?', '[{"id":"a","text":"Maintain confidentiality — the hallucinations are part of the illness"},{"id":"b","text":"Warn the identified co-worker and notify the appropriate authorities (Tarasoff duty to protect)"},{"id":"c","text":"Increase antipsychotic medications without provider order"},{"id":"d","text":"Document the hallucinations and monitor without action"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Tarasoff v. Regents (duty to protect): when a patient makes a credible, specific threat against an identifiable third party, clinicians have a legal and ethical duty to warn the potential victim and authorities. Confidentiality is overridden by the duty to protect. This must be reported to the treatment team immediately.', '', '', '', 'published'),
  ('Pediatrics', 'mcq', 'A 4-year-old is prescribed amoxicillin 250 mg every 8 hours. The available suspension is 125 mg/5 mL. How many mL should the nurse administer per dose?', '[{"id":"a","text":"5 mL"},{"id":"b","text":"10 mL"},{"id":"c","text":"15 mL"},{"id":"d","text":"2.5 mL"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Desired/Available × Volume: 250 mg ÷ 125 mg × 5 mL = 10 mL. Always use weight-based dosing verification and a calibrated oral syringe for pediatric liquid medications. Never use household teaspoons (1 tsp ≈ 5 mL but measurement is imprecise).', '', '', '', 'published'),
  ('Maternal and Newborn', 'mcq', 'A patient who is Rh-negative delivers an Rh-positive baby. Which medication should the nurse administer within 72 hours?', '[{"id":"a","text":"Betamethasone (to mature fetal lungs for the next pregnancy)"},{"id":"b","text":"RhoGAM (Rh immune globulin)"},{"id":"c","text":"Anti-D immunoglobulin is only needed if the mother has already been sensitized"},{"id":"d","text":"Vitamin K to prevent bleeding"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Rh-negative mother + Rh-positive fetus = risk of maternal sensitization from fetal blood mixing. RhoGAM (Rh immune globulin) must be given within 72 hours of delivery to prevent maternal antibody formation. Without it, subsequent Rh-positive pregnancies risk hemolytic disease of the fetus/newborn.', '', '', '', 'published'),
  ('Safety and Infection Control', 'mcq', 'A nurse correctly identifies a patient using two identifiers before administering medication. The identifiers checked are:', '[{"id":"a","text":"Room number and bed assignment"},{"id":"b","text":"Patient name and date of birth (or MRN)"},{"id":"c","text":"Patient name and diagnosis"},{"id":"d","text":"Patient name and nurse assignment"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'The Joint Commission requires two patient identifiers before procedures, medication, blood products, or specimen collection. Approved identifiers: name, DOB, MRN. Room number is NOT a patient identifier — patient transfers make it unreliable. Using room/bed number as an identifier is a common wrong-patient error source.', '', '', '', 'published'),
  ('Leadership and Management', 'mcq', 'A nurse suspects that a patient is experiencing elder abuse at home. Which action is required?', '[{"id":"a","text":"Ask the family member accompanying the patient if abuse is occurring"},{"id":"b","text":"Document suspicions in the chart and let the provider decide"},{"id":"c","text":"Report the suspicion to adult protective services (APS) per state mandated reporter law"},{"id":"d","text":"Discuss findings with the interdisciplinary team at next week''s meeting"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Nurses are mandated reporters in all U.S. states. Suspected elder abuse, neglect, or exploitation MUST be reported to Adult Protective Services (APS) — the nurse does not need proof, only reasonable suspicion. Reports should be made promptly; waiting for a team meeting may allow continued harm. Questioning the suspected abuser can escalate danger.', '', '', '', 'published'),
  ('NGN Case Studies', 'sata', 'A nurse is caring for a patient post-cardiac catheterization via the radial artery approach. Which assessments are essential? (Select all that apply)', '[{"id":"a","text":"Radial pulse distal to the access site"},{"id":"b","text":"Capillary refill and color of the hand"},{"id":"c","text":"Femoral groin site for hematoma"},{"id":"d","text":"Patient reports of hand numbness or tingling"},{"id":"e","text":"TR Band (hemostatic band) pressure and bleeding at wrist site"}]'::jsonb, '{"ids":["a","b","d","e"]}'::jsonb, 'Radial access: assess the distal radial pulse, color/warmth/capillary refill of hand (ischemia risk), sensory symptoms (numbness = nerve/arterial compromise), and the TR Band for bleeding/hematoma at the wrist. The femoral groin site is NOT relevant for radial access — that applies to femoral approach.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient is prescribed transdermal nitroglycerin patches for angina prophylaxis. Which instruction prevents tolerance?', '[{"id":"a","text":"Apply a new patch every 12 hours without removing the old one"},{"id":"b","text":"Remove the patch for 10–12 hours each day (nitrate-free interval)"},{"id":"c","text":"Use the same skin site each time for consistent absorption"},{"id":"d","text":"Apply the patch to the chest only for cardiac benefit"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Continuous nitrate exposure causes tolerance within 24 hours. A nitrate-free interval of 10–12 hours (typically overnight) prevents tolerance. Rotate application sites (avoid distal extremities, skin folds, hairy areas). Wash hands after applying and avoid the nitroglycerin during the patch-free period if angina occurs.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with myasthenia gravis is in crisis. Which finding helps the nurse differentiate myasthenic crisis from cholinergic crisis?', '[{"id":"a","text":"Both crises present identically — only Tensilon test can differentiate"},{"id":"b","text":"Cholinergic crisis includes SLUDGE symptoms (salivation, lacrimation, urination, defecation, GI cramping, emesis)"},{"id":"c","text":"Myasthenic crisis presents with dry mucous membranes and constipation"},{"id":"d","text":"Cholinergic crisis responds to anticholinesterase medications"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Myasthenic crisis: too little acetylcholine effect (needs more pyridostigmine). Cholinergic crisis: too much acetylcholine (excess pyridostigmine → SLUDGE symptoms). The Tensilon (edrophonium) test differentiates: if symptoms improve = myasthenic; if worsen = cholinergic. Cholinergic crisis requires holding pyridostigmine and giving atropine.', '', '', '', 'published'),
  ('Medical-Surgical', 'sata', 'A nurse is caring for a patient in acute respiratory distress syndrome (ARDS) on mechanical ventilation. Which lung-protective strategies are used? (Select all that apply)', '[{"id":"a","text":"Low tidal volume ventilation (4–6 mL/kg ideal body weight)"},{"id":"b","text":"High PEEP to recruit alveoli"},{"id":"c","text":"FiO2 as high as needed to maintain SpO2 >95%"},{"id":"d","text":"Prone positioning for severe ARDS"},{"id":"e","text":"Permissive hypercapnia (allowing PaCO2 to rise modestly)"}]'::jsonb, '{"ids":["a","b","d","e"]}'::jsonb, 'ARDS lung-protective ventilation (ARDSnet): low tidal volume (4–6 mL/kg IBW) prevents volutrauma, high PEEP keeps alveoli open, prone positioning (>12 hours/day) improves V/Q matching, permissive hypercapnia is accepted to allow low tidal volumes. Minimize FiO2 (target SpO2 88–95%) to prevent O2 toxicity.', '', '', '', 'published'),
  ('Mental Health', 'sata', 'A patient is on a 1:1 safety watch for suicidal ideation. Which environmental modifications are essential? (Select all that apply)', '[{"id":"a","text":"Remove sharps, cords, and belts from the patient''s environment"},{"id":"b","text":"Search belongings for contraband upon admission"},{"id":"c","text":"Allow the patient to keep their cell phone for distress calls"},{"id":"d","text":"Use tamper-resistant fixtures and breakaway shower bars"},{"id":"e","text":"Use paper or foam cups instead of glass or ceramic"}]'::jsonb, '{"ids":["a","b","d","e"]}'::jsonb, 'Environmental safety for suicidal patients: remove ligature risks (cords, belts, shoelaces), sharps, glass objects; tamper-resistant environmental features; paper/foam products. Cell phones pose a risk (cords, ability to access means, stressful content). All belongings are searched on admission to a psychiatric unit.', '', '', '', 'published'),
  ('Safety and Infection Control', 'sata', 'A nurse is preventing hospital-acquired pressure injuries in a bedridden patient. Which interventions are evidence-based? (Select all that apply)', '[{"id":"a","text":"Reposition the patient every 2 hours"},{"id":"b","text":"Massage bony prominences vigorously to increase circulation"},{"id":"c","text":"Use a pressure-redistribution mattress"},{"id":"d","text":"Keep skin clean and dry, apply moisture barrier cream"},{"id":"e","text":"Use heel lift boots or pillows to float heels off the bed"}]'::jsonb, '{"ids":["a","c","d","e"]}'::jsonb, 'Evidence-based pressure injury prevention: reposition every 2 hours, pressure-redistribution support surface, moisture management (brief hygiene), heel offloading. Do NOT massage bony prominences — this disrupts already-compromised tissue and increases injury risk. The Braden Scale guides risk assessment.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient is receiving continuous enteral tube feeding. The residual volume is 350 mL. What action should the nurse take?', '[{"id":"a","text":"Continue the feeding at the current rate"},{"id":"b","text":"Discard the residual and continue the feeding"},{"id":"c","text":"Hold the feeding, return the residual, and notify the provider or follow the protocol"},{"id":"d","text":"Increase the feeding rate to compensate for the residual"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'A gastric residual >200–250 mL (per most facility protocols) indicates impaired gastric emptying. Hold the feeding, return the residual (to prevent electrolyte loss), and assess for aspiration risk. Notify the provider. Follow facility protocol — thresholds vary. Never increase the rate with a large residual.', '', '', '', 'published'),
  ('Medical-Surgical', 'sata', 'A nurse is assessing a patient for dehydration. Which findings are consistent? (Select all that apply)', '[{"id":"a","text":"Decreased skin turgor (tenting over sternum or hand)"},{"id":"b","text":"Urine specific gravity 1.030"},{"id":"c","text":"Bounding peripheral pulses"},{"id":"d","text":"Dry mucous membranes"},{"id":"e","text":"Orthostatic hypotension"}]'::jsonb, '{"ids":["a","b","d","e"]}'::jsonb, 'Dehydration: poor skin turgor, concentrated urine (SG >1.025), dry mucous membranes, orthostatic hypotension (BP drop >20 systolic when standing), weak/thready pulse (not bounding). Bounding pulses indicate fluid overload or high cardiac output states.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with a colostomy is concerned because the stoma output is liquid. The nurse assesses that the colostomy is located in the ascending colon. What is the most appropriate response?', '[{"id":"a","text":"\"Liquid output is abnormal — report this to your surgeon.\""},{"id":"b","text":"\"Liquid output is expected from a right-sided (ascending) colostomy because absorption is incomplete.\""},{"id":"c","text":"\"Increase dietary fiber to solidify the stool output.\""},{"id":"d","text":"\"Irrigate the colostomy daily to regulate output.\""}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Colostomy output consistency depends on location: right-sided (ascending) = liquid (less water absorbed), transverse = semi-formed, sigmoid/descending = formed. Liquid output from a right colostomy is expected and normal. Irrigation is only appropriate for sigmoid colostomies.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient takes St. John''s Wort for mild depression and is prescribed indinavir for HIV. What is the nurse''s concern?', '[{"id":"a","text":"St. John''s Wort has no significant drug interactions"},{"id":"b","text":"St. John''s Wort induces CYP3A4, reducing indinavir plasma levels and risk of treatment failure"},{"id":"c","text":"Combining these causes serotonin syndrome"},{"id":"d","text":"St. John''s Wort enhances indinavir causing toxicity"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'St. John''s Wort is a potent CYP3A4 inducer — it increases drug metabolism and reduces plasma levels of many medications including antiretrovirals (indinavir, efavirenz), oral contraceptives, warfarin, and cyclosporine. For HIV medications, this can cause sub-therapeutic levels and treatment failure/resistance.', '', '', '', 'published'),
  ('Leadership and Management', 'sata', 'A nurse is preparing to perform a time-out before a surgical procedure. Which elements are confirmed? (Select all that apply)', '[{"id":"a","text":"Patient identity using two identifiers"},{"id":"b","text":"Correct surgical site marked by the surgeon"},{"id":"c","text":"Procedure to be performed"},{"id":"d","text":"Patient''s insurance coverage"},{"id":"e","text":"Required equipment and implants are available"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'Universal Protocol time-out (Joint Commission): correct patient identity, correct procedure, correct surgical site (marked), positioning, required implants/equipment available. All team members must agree before proceeding. Insurance information is administrative and is NOT part of the clinical time-out.', '', '', '', 'published'),
  ('NGN Case Studies', 'mcq', 'A nurse is triaging 4 patients. Which patient has the highest priority?', '[{"id":"a","text":"A 45-year-old with a migraine, vomiting, and pain 8/10"},{"id":"b","text":"A 70-year-old with new onset slurred speech and right-sided arm weakness that started 45 minutes ago"},{"id":"c","text":"A 30-year-old with an ankle sprain, swelling, and pain 5/10"},{"id":"d","text":"A 55-year-old with a chronic back pain exacerbation"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Sudden onset neurological symptoms (slurred speech, unilateral weakness) within 4.5 hours = possible ischemic stroke — time-critical. "Time is brain" — every minute of delay kills neurons. Activate the stroke team immediately. FAST: Face drooping, Arm weakness, Speech difficulty, Time to call. The 30-min window for CT and 60-min window for tPA are benchmarks.', '', '', '', 'published'),
  ('Maternal and Newborn', 'sata', 'A nurse is teaching a pregnant patient about danger signs requiring immediate medical evaluation. Which symptoms are included? (Select all that apply)', '[{"id":"a","text":"Sudden severe headache with visual changes"},{"id":"b","text":"Decreased fetal movement"},{"id":"c","text":"Vaginal bleeding at any gestational age"},{"id":"d","text":"Mild ankle swelling at 36 weeks"},{"id":"e","text":"Severe upper right quadrant pain"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'Obstetric danger signs: severe headache + visual changes (preeclampsia/eclampsia), decreased fetal movement (possible fetal distress), any vaginal bleeding, RUQ pain (HELLP syndrome/hepatic capsule distension). Mild ankle edema at 36 weeks is normal. "HELLP": Hemolysis, Elevated Liver enzymes, Low Platelets.', '', '', '', 'published'),
  ('Pediatrics', 'mcq', 'A nurse is performing a pain assessment on a 3-year-old who cannot verbalize pain. Which scale is most appropriate?', '[{"id":"a","text":"Numeric Rating Scale (0–10)"},{"id":"b","text":"FLACC scale (Face, Legs, Activity, Cry, Consolability)"},{"id":"c","text":"Visual Analog Scale"},{"id":"d","text":"McGill Pain Questionnaire"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'FLACC is a behavioral pain assessment tool validated for non-verbal children 2 months–7 years. It scores 5 behavioral indicators (0–2 each, total 0–10). Numeric scales require verbal/cognitive ability (appropriate for ≥6–8 years). The Wong-Baker FACES scale is appropriate for ≥3 years who can point to a face.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient receives tissue plasminogen activator (tPA) for DVT. Which finding 1 hour later requires immediate provider notification?', '[{"id":"a","text":"A mild headache rated 2/10"},{"id":"b","text":"Blood oozing from IV sites"},{"id":"c","text":"Sudden confusion and left-sided arm weakness"},{"id":"d","text":"Temperature increase of 0.5°C"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'New neurological deficits (confusion, focal weakness) after thrombolytic therapy (tPA) = intracranial hemorrhage until proven otherwise — a life-threatening emergency. Stop the tPA infusion immediately and notify the provider. Order emergent CT scan. IV site oozing is expected and managed with pressure.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient on continuous cardiac monitoring develops a rhythm with no discernible P waves, an irregularly irregular pattern, and a ventricular rate of 110 bpm. The nurse identifies this as:', '[{"id":"a","text":"Atrial flutter with 2:1 conduction"},{"id":"b","text":"Atrial fibrillation with rapid ventricular response"},{"id":"c","text":"Third-degree (complete) heart block"},{"id":"d","text":"Ventricular tachycardia"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Atrial fibrillation: chaotic atrial activity (no true P waves, "fibrillatory baseline"), irregularly irregular R-R intervals, variable ventricular rate. A-fib with RVR (rate >100) requires rate control (beta-blockers, calcium channel blockers, digoxin). Anticoagulation is needed for stroke prevention.', '', '', '', 'published'),
  ('Safety and Infection Control', 'mcq', 'A patient requires wound irrigation with a large volume of saline. Which equipment provides the most effective irrigation pressure to remove debris?', '[{"id":"a","text":"Gentle pour from a saline bottle"},{"id":"b","text":"Bulb syringe irrigation"},{"id":"c","text":"35 mL syringe with a 19-gauge angiocath at 8–12 psi"},{"id":"d","text":"Whirlpool hydrotherapy"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Effective wound irrigation requires 8–12 psi to remove bacteria and debris without damaging tissue. A 35 mL syringe with a 19-gauge angiocath delivers approximately 8–10 psi. Bulb syringes deliver <1 psi (inadequate). High-pressure devices (>15 psi) can drive bacteria into tissue.', '', '', '', 'published'),
  ('NGN Case Studies', 'sata', 'A nurse is caring for a patient with Type 1 DM admitted for hypoglycemia unawareness. Which teaching points are essential for discharge? (Select all that apply)', '[{"id":"a","text":"Check blood glucose more frequently, especially before driving"},{"id":"b","text":"Keep fast-acting glucose sources available at all times"},{"id":"c","text":"Wear or carry medical ID indicating diabetic status"},{"id":"d","text":"Eat only when blood glucose is above 180 mg/dL"},{"id":"e","text":"Teach family members how to administer glucagon"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'Hypoglycemia unawareness (absent warning symptoms): frequent glucose monitoring (CGM strongly recommended), always carry glucose (15g fast carbs), medical ID for emergencies, family glucagon training for severe episodes. Eating only when glucose >180 encourages chronic hyperglycemia — incorrect. Target pre-meal glucose per provider plan.', '', '', '', 'published'),
  ('Mental Health', 'mcq', 'A patient with dementia becomes agitated and combative every evening (sundowning). Which nursing intervention is most effective?', '[{"id":"a","text":"Administer haloperidol routinely at 1600 hours to prevent agitation"},{"id":"b","text":"Restrain the patient during evening hours for safety"},{"id":"c","text":"Increase meaningful activity in the afternoon and ensure adequate lighting in the evening"},{"id":"d","text":"Move the patient to a quiet room with no stimulation"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Sundowning management: non-pharmacological first. Meaningful daytime activity (prevents boredom and sleep during day), adequate evening lighting (reduces shadows that trigger confusion), consistent routine, calming music, caregiver presence. Routine antipsychotics increase fall risk and are not first-line. Restraints worsen agitation.', '', '', '', 'published'),
  ('Pediatrics', 'mcq', 'A 2-year-old child is seen for a well-child visit. The nurse notes the child says 50 words and uses 2-word phrases. What is the nurse''s assessment?', '[{"id":"a","text":"Delayed — refer for speech evaluation immediately"},{"id":"b","text":"Advanced — most 2-year-olds say fewer words"},{"id":"c","text":"Within normal limits — 50+ words and 2-word combinations are expected at age 2"},{"id":"d","text":"Slightly delayed — typical 2-year-olds use only 10–15 words"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Expected language development at 24 months: vocabulary of ≥50 words, 2-word phrases ("more milk"), and beginning of short sentences. Red flags at 2 years: <50 words, no 2-word phrases, loss of previously acquired language (regression). This child''s development is appropriate.', '', '', '', 'published'),
  ('Leadership and Management', 'mcq', 'A nurse is discharging a patient who speaks limited English. The patient''s adult child offers to interpret. What is the most appropriate action?', '[{"id":"a","text":"Allow the family member to interpret — it is more comfortable for the patient"},{"id":"b","text":"Use a professional medical interpreter (in-person, video, or phone)"},{"id":"c","text":"Speak slowly and use gestures to convey information"},{"id":"d","text":"Provide only written discharge instructions in English"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Federal law (Title VI, Civil Rights Act) requires healthcare facilities receiving federal funding to provide meaningful access to language services. Family interpreters risk inaccuracy, omission, and HIPAA violations. A certified medical interpreter ensures accuracy and maintains confidentiality. Ask the patient if they prefer a professional interpreter.', '', '', '', 'published'),
  ('Pharmacology', 'mcq', 'A patient with bipolar disorder taking lithium has the following levels on two consecutive days: 1.8 mEq/L and 2.3 mEq/L. The patient has coarse tremors and is confused. What is the priority action?', '[{"id":"a","text":"Administer the next lithium dose and recheck levels in 12 hours"},{"id":"b","text":"Hold lithium, notify provider, prepare for IV hydration and monitoring"},{"id":"c","text":"Administer activated charcoal for detoxification"},{"id":"d","text":"Increase fluid intake to 2 L orally and recheck level tomorrow"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Lithium toxicity: level 2.3 mEq/L with coarse tremor and confusion = severe toxicity (>2.0 mEq/L). Immediately: HOLD lithium, notify provider, IV saline (promotes renal lithium excretion), monitor neurological status, cardiac rhythm. Severe cases require hemodialysis. There is NO specific antidote for lithium.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with heart failure has jugular venous distension (JVD), 3+ pitting edema, and bilateral crackles. Which position is most therapeutic?', '[{"id":"a","text":"Flat supine to maximize preload"},{"id":"b","text":"Trendelenburg to increase venous return"},{"id":"c","text":"High Fowler''s (90 degrees) with legs dependent"},{"id":"d","text":"Left lateral with head of bed elevated 15 degrees"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'High Fowler''s with legs dependent (dangling): reduces preload (fluid shifts from central to peripheral circulation), decreases pulmonary congestion, improves diaphragmatic excursion and breathing. Supine and Trendelenburg increase venous return (increase preload) — contraindicated in fluid overload. This is the first-line non-pharmacologic intervention for acute decompensated heart failure.', '', '', '', 'published'),
  ('Maternal and Newborn', 'mcq', 'A nurse is assessing a 2-hour-old newborn. Which finding requires immediate intervention?', '[{"id":"a","text":"Respiratory rate of 48 breaths per minute"},{"id":"b","text":"Acrocyanosis (blue hands and feet)"},{"id":"c","text":"Central cyanosis (blue lips and trunk)"},{"id":"d","text":"Molding of the skull from vaginal delivery"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Central cyanosis (lips, tongue, trunk) in a newborn indicates systemic hypoxia — possible congenital heart defect, respiratory distress, or sepsis. This is NEVER normal and requires immediate assessment and intervention. Acrocyanosis (peripheral) is normal in the first 24–48 hours. RR 40–60 and molding are normal newborn findings.', '', '', '', 'published'),
  ('Safety and Infection Control', 'mcq', 'A nurse is administering a blood transfusion. Which action is most important to ensure patient safety?', '[{"id":"a","text":"Prime the tubing with dextrose solution before connecting blood"},{"id":"b","text":"Verify blood product with another licensed nurse using two patient identifiers and blood bank information"},{"id":"c","text":"Administer the entire unit as quickly as possible to prevent bacterial growth"},{"id":"d","text":"Start the transfusion and return to check in 2 hours"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Blood transfusion safety: two licensed nurses verify the blood product at the bedside — patient name, DOB, MRN, blood type, expiration date, and unit number match between the patient, wristband, and blood bank label. Fatal hemolytic transfusion reactions occur from wrong-patient errors. Use only 0.9% NS (never dextrose — causes hemolysis).', '', '', '', 'published'),
  ('NGN Case Studies', 'mcq', 'A nurse is reviewing morning labs for a patient on day 3 of broad-spectrum antibiotics: WBC 24,000, temperature 39.4°C, new onset diarrhea (5–6 loose stools), crampy abdominal pain. Which pathogen is most likely responsible?', '[{"id":"a","text":"Staphylococcus aureus (MRSA)"},{"id":"b","text":"Clostridioides difficile (C. diff)"},{"id":"c","text":"Pseudomonas aeruginosa"},{"id":"d","text":"Candida albicans"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'C. difficile colitis: antibiotic use (disrupts normal flora), new-onset diarrhea (≥3 loose stools/day), crampy pain, leukocytosis, fever. Contact precautions immediately. Diagnosis: C. diff toxin assay. Treatment: oral vancomycin or fidaxomicin. Metronidazole is second-line. ALWAYS wash hands with soap and water (alcohol-based sanitizer does not kill C. diff spores).', '', '', '', 'published'),
  ('Pharmacology', 'sata', 'A nurse is caring for a patient taking warfarin. Which substances significantly increase the anticoagulant effect and bleeding risk? (Select all that apply)', '[{"id":"a","text":"Aspirin"},{"id":"b","text":"Cranberry juice in large amounts"},{"id":"c","text":"Vitamin K-rich foods (kale, spinach)"},{"id":"d","text":"Fluconazole (antifungal)"},{"id":"e","text":"Rifampin (antibiotic)"}]'::jsonb, '{"ids":["a","b","d"]}'::jsonb, 'Warfarin interactions: aspirin (adds antiplatelet effect), cranberry juice (inhibits CYP2C9, increases warfarin), fluconazole (inhibits CYP2C9, significantly increases INR). Vitamin K-rich foods DECREASE anticoagulant effect. Rifampin INDUCES CYP enzymes, DECREASING warfarin effect. Consistency of Vit K intake is key — not elimination.', '', '', '', 'published'),
  ('Medical-Surgical', 'mcq', 'A patient with acute gout asks why they should increase fluid intake. The nurse explains:', '[{"id":"a","text":"Fluid dilutes uric acid in the blood and promotes renal excretion"},{"id":"b","text":"Fluids increase uric acid production to stimulate excretion"},{"id":"c","text":"Dehydration has no effect on gout attacks"},{"id":"d","text":"Fluid intake prevents the need for allopurinol"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Gout results from hyperuricemia and urate crystal deposition in joints. Increased fluid intake (2–3 L/day) dilutes uric acid and promotes renal excretion, reducing serum urate levels. Also avoid: purine-rich foods (organ meats, shellfish), alcohol (especially beer), and dehydration. Colchicine is for acute attacks; allopurinol for prevention.', '', '', '', 'published'),
  ('Leadership and Management', 'mcq', 'A nurse is floated to a unit outside their usual practice area. Which action best protects patient safety?', '[{"id":"a","text":"Accept any patient assignment without question to demonstrate flexibility"},{"id":"b","text":"Communicate competency limitations to the charge nurse and only accept assignments within the nurse''s skill level"},{"id":"c","text":"Refuse the float assignment entirely"},{"id":"d","text":"Handle all assigned patients independently without asking for help to avoid appearing incompetent"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Nurses practice within their scope and competency. When floated, communicate honestly about skill limitations (e.g., "I''m not experienced with PICC line care"). Request appropriate orientation and avoid taking high-acuity patients outside your expertise. This protects patients AND the nurse legally. Silence about incompetence is negligence.', '', '', '', 'published'),
  ('Maternal and Newborn', 'mcq', 'A patient is in active labor and requests an epidural. Before administering the epidural, the nurse should:', '[{"id":"a","text":"Obtain verbal consent only since it is an emergency"},{"id":"b","text":"Pre-hydrate with IV fluids, verify platelet count, and obtain informed consent"},{"id":"c","text":"Administer the epidural immediately to reduce maternal stress"},{"id":"d","text":"Check fetal station — epidurals are contraindicated before 8 cm dilation"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Pre-epidural: IV fluid bolus (reduces hypotension risk — common side effect), informed consent, platelet count >80,000 (thrombocytopenia contraindication), baseline FHR documentation. Epidurals are NOT contraindicated at any cervical dilation — this is a common misconception. Maternal hypotension post-epidural → fetal bradycardia; left lateral positioning helps.', '', '', '', 'published'),
  ('NGN Case Studies', 'mcq', 'A nurse is caring for a patient post-kidney transplant on day 5. Labs show: creatinine 3.8 (up from 1.2 yesterday), decreased urine output, weight gain of 2 kg, and the patient reports tenderness over the graft site. Which complication is most likely?', '[{"id":"a","text":"Acute rejection of the transplanted kidney"},{"id":"b","text":"Calcineurin inhibitor nephrotoxicity"},{"id":"c","text":"Urinary tract infection"},{"id":"d","text":"Fluid overload from IV therapy"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Acute rejection (days to months post-transplant): rising creatinine, decreased urine output, weight gain (fluid retention), fever, hypertension, and graft site tenderness. Treatment: high-dose IV corticosteroids, anti-thymocyte globulin. Calcineurin inhibitor toxicity causes gradual rising creatinine without graft tenderness. Notify provider immediately — early treatment preserves the graft.', '', '', '', 'published'),
  ('NGN Case Studies', 'highlight', 'A nurse reviews the following nursing note for a 72-year-old client admitted for a right hip replacement performed this morning. Highlight all findings that require immediate follow-up.', '[]'::jsonb, '{"ids":[]}'::jsonb, 'Immediate follow-up required: SpO₂ 88% on room air (below acceptable threshold, risk of hypoxia), urine output of 15 mL/hr for 3 hours (oliguria, less than 0.5 mL/kg/hr — indicates hypovolemia or AKI), and right calf pain and warmth (classic signs of DVT, a major post-op complication of hip replacement). Temperature 38.1°C and mild incision oozing are expected within first 24 hours post-op and require monitoring, not immediate intervention. HR 88 is within normal limits for a post-op client.', '', '', '', 'published'),
  ('Cardiovascular', 'mcq', 'A client admitted with an acute MI has BP 88/50 mmHg, HR 118 bpm, cool clammy skin, and urine output 15 mL/hr. Which complication does the nurse suspect?', '[{"id":"a","text":"Hypertensive urgency"},{"id":"b","text":"Cardiogenic shock"},{"id":"c","text":"Pulmonary embolism"},{"id":"d","text":"Pericardial tamponade"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Cardiogenic shock: post-MI hypotension + tachycardia + cool/clammy skin + oliguria = the heart cannot pump. Tamponade = Beck''s triad (JVD, muffled sounds, hypotension). PE = pleuritic chest pain + hypoxia.', 'Triad after MI: hypotension + tachy + cold/clammy + low urine = cardiogenic shock. The pump has failed. Peripheral circulation shuts down to preserve core organs.', '', '', 'published'),
  ('Cardiovascular', 'sata', 'A client has left-sided heart failure. Which assessment findings does the nurse expect? Select all that apply.', '[{"id":"a","text":"Bilateral crackles in the lung bases"},{"id":"b","text":"Jugular venous distension"},{"id":"c","text":"Pink frothy sputum"},{"id":"d","text":"Dependent pitting ankle edema"},{"id":"e","text":"S3 gallop heart sound"}]'::jsonb, '{"ids":["a","c","e"]}'::jsonb, 'Left HF backs up into the lungs: crackles, pink frothy sputum (severe pulmonary edema), S3 gallop. JVD and peripheral edema = right HF (backs up into systemic circulation).', 'Left = Lungs. Right = Rest of body. Apply this spatial rule instantly. Left HF = pulmonary. Right HF = peripheral/systemic.', '', '', 'published'),
  ('Cardiovascular', 'mcq', 'A client on IV heparin for DVT has an aPTT of 120 seconds. What is the nurse''s priority action?', '[{"id":"a","text":"Increase the infusion rate"},{"id":"b","text":"Administer protamine sulfate"},{"id":"c","text":"Contact the provider to adjust the rate"},{"id":"d","text":"Repeat the aPTT in 2 hours without changes"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Therapeutic aPTT: 60–100 seconds. At 120 the client is supratherapeutic — high bleeding risk. Notify the provider. Protamine reverses heparin but needs an order. Never independently adjust an infusion.', 'Therapeutic aPTT = 1.5–2.5x normal = 60–100 sec. Above 100 = too much heparin → notify provider. Never adjust an IV infusion without an order.', '', '', 'published'),
  ('Respiratory', 'mcq', 'A client with COPD has ABG: pH 7.32, PaCO₂ 58 mmHg, HCO₃ 28 mEq/L. The nurse interprets this as:', '[{"id":"a","text":"Respiratory alkalosis with metabolic compensation"},{"id":"b","text":"Metabolic acidosis, uncompensated"},{"id":"c","text":"Respiratory acidosis with partial metabolic compensation"},{"id":"d","text":"Mixed respiratory and metabolic alkalosis"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'pH 7.32 = acidosis. PaCO₂ 58 = elevated → respiratory cause. HCO₃ 28 = elevated → kidneys compensating. pH still abnormal = partial compensation. Classic COPD CO₂ retention.', 'ROME: Respiratory Opposite — pH low + PaCO₂ high = respiratory acidosis. Then HCO₃ elevated = kidney compensation. pH still abnormal = partial.', '', '', 'published'),
  ('Respiratory', 'sata', 'A client is placed on airborne precautions. Which actions does the nurse take? Select all that apply.', '[{"id":"a","text":"Place the client in a negative pressure room"},{"id":"b","text":"Wear a surgical mask when entering"},{"id":"c","text":"Wear an N95 respirator before entering"},{"id":"d","text":"Keep the client door closed at all times"},{"id":"e","text":"Client wears a surgical mask during transport"}]'::jsonb, '{"ids":["a","c","d","e"]}'::jsonb, 'Airborne (TB, measles, varicella): negative pressure room, door closed, N95 for staff (NOT surgical mask), client wears surgical mask during transport.', 'Airborne = N95 + negative pressure room. Surgical mask wrong-answer trap: it is used for DROPLET, not airborne. N95 filters tiny airborne particles — surgical masks do not.', '', '', 'published'),
  ('Respiratory', 'mcq', 'A client 30 minutes post-thoracentesis reports sudden sharp chest pain and dyspnea. Breath sounds are absent on the right. The nurse''s first action is to:', '[{"id":"a","text":"Administer the prescribed analgesic"},{"id":"b","text":"Position the client on the affected side"},{"id":"c","text":"Notify the provider immediately"},{"id":"d","text":"Encourage slow deep breathing"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Absent breath sounds + chest pain + dyspnea after thoracentesis = pneumothorax. Life-threatening complication. Notify the provider immediately for chest tube.', 'Post-thoracic procedure + absent breath sounds + dyspnea = pneumothorax until proven otherwise. Always notify provider first — this is an emergency.', '', '', 'published'),
  ('Renal and Urinary', 'mcq', 'A client with CKD has K⁺ 6.4 mEq/L and peaked T waves on the monitor. The nurse implements which intervention first?', '[{"id":"a","text":"Restrict dietary potassium"},{"id":"b","text":"Administer sodium polystyrene sulfonate orally"},{"id":"c","text":"Administer IV calcium gluconate as prescribed"},{"id":"d","text":"Prepare the client for hemodialysis"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Hyperkalemia with cardiac changes needs immediate cardiac membrane stabilization. IV calcium gluconate acts within minutes. Kayexalate removes K⁺ slowly (hours). Dialysis is definitive but not the immediate first step.', 'Hyperkalemia + cardiac changes = cardiac emergency. Stabilize the heart first with calcium gluconate, THEN remove potassium. Stabilize → eliminate.', '', '', 'published'),
  ('Renal and Urinary', 'sata', 'A client is 2 days post-kidney transplant. Which findings require the nurse to notify the provider? Select all that apply.', '[{"id":"a","text":"Urine output 200 mL/hr"},{"id":"b","text":"Creatinine rising from 1.1 to 3.4 mg/dL"},{"id":"c","text":"Temperature 37.2°C (99°F)"},{"id":"d","text":"Graft site tenderness and swelling"},{"id":"e","text":"WBC 11,000/mm³ on tacrolimus"}]'::jsonb, '{"ids":["a","b","d"]}'::jsonb, 'Polyuria, rising creatinine, and graft tenderness signal acute rejection or ATN. Low-grade fever is expected post-op. Mild WBC elevation on immunosuppressants is expected.', 'Post-transplant "3 Cs": Creatinine rising, Clinical graft changes, output Changes (high or low). Any = notify provider. Low-grade fever and mild WBC elevation = expected.', '', '', 'published'),
  ('Endocrine', 'mcq', 'A client with type 1 diabetes is unresponsive with BG 38 mg/dL. An IV is in place. The nurse''s priority intervention is:', '[{"id":"a","text":"Give 4 oz of orange juice orally"},{"id":"b","text":"Administer 50 mL of 50% dextrose IV"},{"id":"c","text":"Administer glucagon 1 mg IM"},{"id":"d","text":"Recheck BG in 15 minutes"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Unresponsive + IV access + severe hypoglycemia = D50W IV (works in 1–3 min). Oral juice is contraindicated when unconscious — aspiration risk. Glucagon IM only when no IV access available.', 'Unresponsive + IV = D50W first. Conscious + no IV = oral glucose. No IV access at all = glucagon IM. IV route is always fastest in a hypoglycemic emergency.', '', '', 'published'),
  ('Endocrine', 'sata', 'A client is admitted in diabetic ketoacidosis. Which findings does the nurse expect? Select all that apply.', '[{"id":"a","text":"Blood glucose > 300 mg/dL"},{"id":"b","text":"Kussmaul respirations"},{"id":"c","text":"Fruity acetone breath"},{"id":"d","text":"Serum pH of 7.48"},{"id":"e","text":"Positive urine ketones"}]'::jsonb, '{"ids":["a","b","c","e"]}'::jsonb, 'DKA: hyperglycemia, metabolic acidosis (pH < 7.35), ketonuria, Kussmaul respirations (resp compensation), fruity breath. pH 7.48 = alkalosis — contradicts DKA acidosis.', 'DKA = High glucose + Low pH + Ketones + Kussmaul breathing. Eliminate pH 7.48 — DKA causes acidosis (low pH), never alkalosis.', '', '', 'published'),
  ('Endocrine', 'mcq', 'A client is newly prescribed levothyroxine. Which instruction does the nurse provide?', '[{"id":"a","text":"Take with a glass of milk for better absorption"},{"id":"b","text":"Take at bedtime to minimize side effects"},{"id":"c","text":"Take on an empty stomach 30–60 minutes before breakfast"},{"id":"d","text":"Discontinue if you experience palpitations"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Levothyroxine absorption is best on an empty stomach 30–60 min before breakfast. Calcium (milk), antacids, and iron block absorption. Palpitations during titration = contact provider, do not self-discontinue.', 'Empty stomach + morning + 30–60 min before food = best levothyroxine absorption. Calcium and iron block it. Never instruct a client to self-discontinue any medication.', '', '', 'published'),
  ('Gastrointestinal', 'mcq', 'A client 2 days post-colostomy says "I should irrigate my colostomy every day to control output." The nurse recognizes this statement indicates:', '[{"id":"a","text":"Correct understanding of colostomy care"},{"id":"b","text":"A need for further teaching"},{"id":"c","text":"An appropriate long-term goal"},{"id":"d","text":"Standard discharge instruction"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Daily colostomy irrigation is NOT universally required and is not standard teaching. It is an optional technique for sigmoid colostomies. Standard teaching: empty at 1/3–1/2 full, skin care, avoid gas-producing foods.', 'Negative event query: "further teaching" = select the incorrect statement. Daily irrigation is not standard. This is a frequent NCLEX wrong-answer trap — do not confuse irrigation with routine pouch emptying.', '', '', 'published'),
  ('Gastrointestinal', 'sata', 'A client has acute pancreatitis. Which interventions are appropriate? Select all that apply.', '[{"id":"a","text":"Keep the client NPO during the acute phase"},{"id":"b","text":"Administer IV opioid analgesics as prescribed"},{"id":"c","text":"Place the client in high-Fowler''s position"},{"id":"d","text":"Monitor serum amylase and lipase"},{"id":"e","text":"Encourage a high-fat diet to rest the pancreas"}]'::jsonb, '{"ids":["a","b","d"]}'::jsonb, 'Pancreatitis: NPO (rests pancreas), IV opioids for pain, monitor amylase/lipase. High-fat diet stimulates enzymes — contraindicated. Semi-Fowler''s with knees flexed for comfort, not high-Fowler''s.', 'REST the pancreas: NPO + pain control + monitor markers. High fat = stimulates enzyme secretion = worse. Eliminate both high fat and high-Fowler''s.', '', '', 'published'),
  ('Neurological', 'mcq', 'A client with elevated ICP has BP 182/50 mmHg, HR 44 bpm, and irregular respirations. The nurse recognizes:', '[{"id":"a","text":"Orthostatic hypotension"},{"id":"b","text":"Cushing''s triad"},{"id":"c","text":"Autonomic dysreflexia"},{"id":"d","text":"Neurogenic shock"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Cushing''s triad = late severe ICP sign: hypertension with wide pulse pressure + bradycardia + irregular respirations. Signals impending brain herniation — medical emergency.', 'Cushing''s triad = Hypertension + Bradycardia + Irregular respirations in a neuro client. Wide pulse pressure is the vascular signature. Memorize this cluster — it is the most tested neuro vital sign pattern.', '', '', 'published'),
  ('Neurological', 'mcq', 'A client presents with sudden right-sided weakness, facial droop, and slurred speech with onset 45 minutes ago. The nurse''s priority action is:', '[{"id":"a","text":"Obtain an ECG"},{"id":"b","text":"Keep NPO and notify the stroke team"},{"id":"c","text":"Administer aspirin 325 mg immediately"},{"id":"d","text":"Prepare for cardiac catheterization"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Stroke symptoms within 4.5 hours = tPA window. Activate stroke team and get CT immediately. NPO for swallowing safety. Never give aspirin until CT rules out hemorrhagic stroke — aspirin in hemorrhagic stroke is fatal.', 'FAST within 4.5 hours = stroke team + CT first. No aspirin until hemorrhage is excluded. Time is brain — every minute = 1.9 million neurons lost.', '', '', 'published'),
  ('Neurological', 'sata', 'A client has a tonic-clonic seizure. Which post-ictal nursing actions are appropriate? Select all that apply.', '[{"id":"a","text":"Position the client laterally"},{"id":"b","text":"Insert an oral airway during active seizing"},{"id":"c","text":"Assess for post-ictal confusion and fatigue"},{"id":"d","text":"Document seizure duration and characteristics"},{"id":"e","text":"Restrain the client''s movements"}]'::jsonb, '{"ids":["a","c","d"]}'::jsonb, 'Post-seizure: lateral position (prevents aspiration), assess post-ictal state, document details. Never insert anything into mouth (injury risk). Never restrain (increases injury).', 'Seizure nursing = Protect, Position lateral, Document. Two classic wrong-answer traps: inserting oral airway and restraining. Both cause harm. Nothing goes in the mouth.', '', '', 'published'),
  ('Musculoskeletal', 'mcq', 'A client 6 hours post-hip replacement reports right foot pain, numbness, pallor, and capillary refill of 4 seconds. The nurse''s first action is to:', '[{"id":"a","text":"Elevate the right leg above heart level"},{"id":"b","text":"Apply a warm compress"},{"id":"c","text":"Notify the provider immediately"},{"id":"d","text":"Administer PRN pain medication"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'The 6 Ps post-orthopedic surgery (pain, pallor, paresthesia + prolonged capillary refill) = neurovascular compromise/compartment syndrome. Medical emergency — notify provider immediately. Elevation worsens arterial perfusion.', '6 Ps: Pain, Pallor, Pulselessness, Paresthesia, Paralysis, Poikilothermia. Any combination post-orthopedic = notify STAT. Pain medication alone treats the symptom while the limb is dying.', '', '', 'published'),
  ('Fluids and Electrolytes', 'mcq', 'A client receiving IV fluids has Na⁺ 128 mEq/L with headache and confusion. The nurse identifies:', '[{"id":"a","text":"Hypernatremia"},{"id":"b","text":"Hyponatremia"},{"id":"c","text":"Hyperkalemia"},{"id":"d","text":"Hypomagnesemia"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Normal Na⁺ = 135–145 mEq/L. Na⁺ 128 = hyponatremia. Low Na⁺ → water shifts into cells → cerebral edema → neurological symptoms: headache, confusion, nausea, seizures.', '128 < 135 = low sodium = hyponatremia. Low Na⁺ → water into brain cells → brain swells → neuro symptoms. Direct knowledge question — know the normal sodium range.', '', '', 'published'),
  ('Fluids and Electrolytes', 'sata', 'A client has K⁺ 2.8 mEq/L. Which manifestations does the nurse expect? Select all that apply.', '[{"id":"a","text":"Muscle weakness and fatigue"},{"id":"b","text":"Peaked T waves on ECG"},{"id":"c","text":"Hypoactive bowel sounds"},{"id":"d","text":"Flat or inverted T waves on ECG"},{"id":"e","text":"U waves on ECG"}]'::jsonb, '{"ids":["a","c","d","e"]}'::jsonb, 'Hypokalemia (K⁺ < 3.5): muscle weakness, hypoactive bowel/ileus, flat/inverted T waves, U waves. Peaked T waves = HYPERKALEMIA.', 'HyperK = Peaked T waves. HypoK = Flat T + U waves. Peaked T is the wrong-answer trap here — eliminate it.', '', '', 'published'),
  ('Complex Care', 'mcq', 'A nurse has 4 assigned clients. Which client is assessed first?', '[{"id":"a","text":"Client with COPD requesting pain medication for chronic back pain"},{"id":"b","text":"Post-appendectomy day 2 asking for a bedpan"},{"id":"c","text":"Client with chest pain radiating to the left arm and diaphoresis"},{"id":"d","text":"Diabetic client reporting hunger before breakfast"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Chest pain + left arm radiation + diaphoresis = potential MI = life-threatening emergency. The other clients have non-life-threatening, stable needs.', 'Priority = ABC. Ask: "Who could die in the next few minutes?" Chest pain + radiation + diaphoresis = possible MI = first. Apply this decision rule every time.', '', '', 'published'),
  ('Complex Care', 'mcq', 'A client in septic shock is on norepinephrine. Which finding best indicates treatment is working?', '[{"id":"a","text":"Serum lactate falling from 6.2 to 2.1 mmol/L"},{"id":"b","text":"Temperature falling from 39.8°C to 37.1°C"},{"id":"c","text":"HR falling from 118 to 98 bpm"},{"id":"d","text":"WBC falling from 22,000 to 14,000/mm³"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Falling serum lactate = gold standard for improving tissue perfusion in septic shock. Lactate rises during anaerobic metabolism. Falling lactate = cells are receiving oxygen = perfusion is restored.', 'Septic shock goal = restore tissue perfusion. Lactate is the direct cellular oxygen marker. Temperature and WBC reflect infection control, not perfusion. Falling lactate = treatment working.', '', '', 'published'),
  ('Oncology and Hematology', 'mcq', 'A client on chemotherapy has an ANC of 450/mm³. The nursing priority is to:', '[{"id":"a","text":"Administer a platelet transfusion"},{"id":"b","text":"Initiate neutropenic precautions and monitor for infection"},{"id":"c","text":"Restrict all visitors from the room"},{"id":"d","text":"Place the client on contact precautions"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'ANC < 500/mm³ = severe neutropenia = highest infection risk. Neutropenic precautions protect the immunocompromised client from the environment (reverse isolation). Platelets address thrombocytopenia. Not all visitors restricted — healthy visitors with good hand hygiene may visit.', 'ANC < 500 = neutropenic precautions. These protect the client FROM pathogens (reverse/protective isolation). Contact precautions protect others FROM the client. Know which direction protection flows.', '', '', 'published'),
  ('Oncology and Hematology', 'sata', 'A client develops chills, fever, low back pain, and hypotension 20 minutes into a transfusion. The nurse takes which actions? Select all that apply.', '[{"id":"a","text":"Stop the transfusion immediately"},{"id":"b","text":"Slow the rate and continue monitoring"},{"id":"c","text":"Keep IV open with normal saline"},{"id":"d","text":"Notify the blood bank and provider"},{"id":"e","text":"Send the blood bag and tubing to the lab"}]'::jsonb, '{"ids":["a","c","d","e"]}'::jsonb, 'Acute hemolytic transfusion reaction (blood type mismatch): STOP immediately, maintain IV with NS using new tubing, notify provider and blood bank, send blood bag + tubing for analysis. Never slow and continue.', 'Hemolytic reaction = STOP — KEEP LINE WITH NS — NOTIFY — SEND BAG. Never slow and continue. The bag must return to the blood bank. This is a life-threatening reaction.', '', '', 'published'),
  ('Perioperative Care', 'sata', 'A nurse completes a pre-operative assessment. Which findings require notifying the provider? Select all that apply.', '[{"id":"a","text":"Client takes warfarin 5 mg daily"},{"id":"b","text":"Client has a latex allergy"},{"id":"c","text":"Hemoglobin 14.2 g/dL"},{"id":"d","text":"Client takes St. John''s Wort herbal supplement"},{"id":"e","text":"BP 128/76 mmHg"}]'::jsonb, '{"ids":["a","b","d"]}'::jsonb, 'Report: warfarin (bleeding risk — may need to be held); latex allergy (OR must be latex-free, anaphylaxis risk); St. John''s Wort (interacts with anesthesia — must stop 2 weeks pre-op). Normal Hgb and BP do not require reporting.', 'Pre-op safety flags: anticoagulants, allergies (especially latex), herbals. Normal labs and vital signs within range = no notification needed. Herbals that interfere: St. John''s Wort, garlic, ginkgo, ginseng.', '', '', 'published'),
  ('Medication Administration', 'mcq', 'Which situation requires the nurse to withhold the medication and contact the provider?', '[{"id":"a","text":"Client on digoxin has apical pulse of 54 bpm"},{"id":"b","text":"Client on metformin has BG of 210 mg/dL"},{"id":"c","text":"Client on lisinopril has BP 142/88 mmHg"},{"id":"d","text":"Client on ferrous sulfate reports dark-colored stools"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Hold digoxin when apical pulse < 60 bpm. Digoxin further slows the heart — bradycardia below 60 is a contraindication. Dark stools with iron are expected. Metformin at BG 210 is within management range. Lisinopril is given for hypertension — BP 142/88 does not warrant withholding.', 'Digoxin rule: apical pulse < 60 = hold and notify. Always count apical for a full minute before giving digoxin. One of the most tested medication safety rules on NCLEX. Know the hold parameters.', '', '', 'published'),
  ('Cardiovascular', 'mcq', 'A client with heart failure reports new shortness of breath while lying flat and has crackles halfway up both lung fields. Which prescription should the nurse question?', '[{"id":"a","text":"Furosemide 40 mg IV now"},{"id":"b","text":"Restrict fluids to 1.5 L/day"},{"id":"c","text":"Infuse 0.9% saline at 150 mL/hr"},{"id":"d","text":"Obtain daily weights each morning"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Rapid isotonic fluid infusion can worsen pulmonary congestion in heart failure. Diuretics, fluid restriction, and daily weights are expected management.', 'In heart failure, new crackles plus orthopnea means fluid is already in the lungs. Do not add more fluid unless there is a compelling reason.', 'Physiological Integrity', 'Analyze Cues', 'published'),
  ('Cardiovascular', 'mcq', 'A client develops chest pain after walking to the bathroom. Which action should the nurse take first?', '[{"id":"a","text":"Call the provider"},{"id":"b","text":"Obtain a 12-lead ECG"},{"id":"c","text":"Stop activity and assist the client to rest"},{"id":"d","text":"Administer morphine as prescribed"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'The first action is to decrease myocardial oxygen demand by stopping activity and placing the client at rest. ECG and medications follow rapid assessment and stabilization.', 'For angina questions, first reduce oxygen demand: stop activity, rest, then assess and treat.', 'Physiological Integrity', 'Take Action', 'published'),
  ('Cardiovascular', 'mcq', 'Which finding is most concerning after femoral cardiac catheterization?', '[{"id":"a","text":"Blood pressure 118/74 mmHg"},{"id":"b","text":"Pedal pulse weaker than baseline"},{"id":"c","text":"Client reports needing to void"},{"id":"d","text":"Small bruise at the insertion site"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'A weaker distal pulse may indicate arterial occlusion or impaired perfusion after catheterization and requires immediate action. A small bruise and urinary urgency can be expected.', 'After cath, think circulation below the insertion site: pulse, color, temperature, sensation, movement.', 'Physiological Integrity', 'Recognize Cues', 'published'),
  ('Cardiovascular', 'mcq', 'A client taking warfarin has an INR of 6.2 and bleeding gums. Which order should the nurse anticipate?', '[{"id":"a","text":"Vitamin K"},{"id":"b","text":"Protamine sulfate"},{"id":"c","text":"Aspirin"},{"id":"d","text":"Additional warfarin"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Vitamin K reverses warfarin. Protamine reverses heparin. Aspirin and more warfarin increase bleeding risk.', 'Match antidotes: warfarin = vitamin K; heparin = protamine.', 'Physiological Integrity', 'Generate Solutions', 'published'),
  ('Respiratory', 'mcq', 'A client with COPD is receiving oxygen at 6 L/min by nasal cannula and becomes increasingly drowsy. Which action should the nurse take first?', '[{"id":"a","text":"Increase oxygen to 10 L/min"},{"id":"b","text":"Assess respiratory rate and oxygen saturation"},{"id":"c","text":"Encourage oral fluids"},{"id":"d","text":"Place the client flat in bed"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Increasing drowsiness may reflect carbon dioxide retention or worsening respiratory failure. The nurse first assesses ventilation and oxygenation.', 'Change in level of consciousness in COPD can mean CO2 retention. Assess breathing before changing therapy.', 'Physiological Integrity', 'Recognize Cues', 'published'),
  ('Respiratory', 'mcq', 'Which arterial blood gas result requires the most immediate follow-up?', '[{"id":"a","text":"pH 7.39, PaCO2 40, HCO3 24"},{"id":"b","text":"pH 7.31, PaCO2 60, HCO3 26"},{"id":"c","text":"pH 7.45, PaCO2 36, HCO3 24"},{"id":"d","text":"pH 7.36, PaCO2 42, HCO3 23"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'A low pH with elevated PaCO2 indicates respiratory acidosis, which may signal hypoventilation and respiratory failure.', 'ROME: pH low and CO2 high move opposite, so respiratory acidosis.', 'Physiological Integrity', 'Analyze Cues', 'published'),
  ('Respiratory', 'mcq', 'A client with pneumonia has SpO2 86%, respiratory rate 32/min, and confusion. Which action is priority?', '[{"id":"a","text":"Collect sputum culture"},{"id":"b","text":"Apply oxygen as prescribed"},{"id":"c","text":"Teach incentive spirometry"},{"id":"d","text":"Document expected findings"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Hypoxemia with confusion requires immediate oxygenation support. Cultures and teaching can occur after stabilizing airway and breathing.', 'ABC priority: low oxygen plus confusion means the brain is not getting oxygen.', 'Physiological Integrity', 'Prioritize Hypotheses', 'published'),
  ('Respiratory', 'mcq', 'Which instruction is most important for a client using an albuterol inhaler before a corticosteroid inhaler?', '[{"id":"a","text":"Use albuterol first, wait several minutes, then use the corticosteroid"},{"id":"b","text":"Use the corticosteroid first to open the airways"},{"id":"c","text":"Do not rinse the mouth after corticosteroid use"},{"id":"d","text":"Use both inhalers only when symptoms are severe"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'A bronchodilator is used first to open airways, improving delivery of the corticosteroid. The client should rinse the mouth after inhaled steroids.', 'Bronchodilator before steroid: open the airway, then deliver the anti-inflammatory medication.', 'Physiological Integrity', 'Take Action', 'published'),
  ('Renal and Urinary', 'mcq', 'A client with chronic kidney disease has potassium 6.1 mEq/L. Which assessment finding is most important?', '[{"id":"a","text":"Dry skin"},{"id":"b","text":"Peaked T waves"},{"id":"c","text":"Poor appetite"},{"id":"d","text":"Mild ankle edema"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Hyperkalemia can cause life-threatening dysrhythmias. Peaked T waves are a classic ECG sign requiring urgent intervention.', 'High potassium hurts the heart first. ECG changes are the danger cue.', 'Physiological Integrity', 'Recognize Cues', 'published'),
  ('Renal and Urinary', 'mcq', 'Which client statement about hemodialysis access needs correction?', '[{"id":"a","text":"I will avoid blood pressure readings in the access arm"},{"id":"b","text":"I will check for a thrill every day"},{"id":"c","text":"I can sleep with my access arm under my body"},{"id":"d","text":"I will report redness or drainage"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Pressure on the access arm can impair blood flow and clot the fistula or graft. The other statements are appropriate.', 'Protect the access: no pressure, no sticks, no BP, check thrill/bruit.', 'Physiological Integrity', 'Evaluate Outcomes', 'published'),
  ('Renal and Urinary', 'mcq', 'A client with acute kidney injury has urine output of 18 mL/hr for 4 hours. Which action is priority?', '[{"id":"a","text":"Encourage high-protein foods"},{"id":"b","text":"Notify the provider"},{"id":"c","text":"Restrict all fluids permanently"},{"id":"d","text":"Document as normal"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Urine output below 30 mL/hr indicates oliguria and may reflect worsening renal perfusion or injury. Prompt follow-up is needed.', 'Minimum urine output is 30 mL/hr. Below that is a perfusion problem until proven otherwise.', 'Physiological Integrity', 'Take Action', 'published'),
  ('Endocrine', 'mcq', 'A client with diabetes is shaky, diaphoretic, and has blood glucose 48 mg/dL. The client is awake and able to swallow. What should the nurse give first?', '[{"id":"a","text":"Regular insulin"},{"id":"b","text":"15 g fast-acting carbohydrate"},{"id":"c","text":"A high-fat meal"},{"id":"d","text":"Metformin"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'An awake client with hypoglycemia should receive 15 g of rapid carbohydrate, then glucose is rechecked. Insulin would worsen hypoglycemia.', 'Conscious hypoglycemia = oral fast sugar. Unconscious = IV dextrose or glucagon.', 'Physiological Integrity', 'Take Action', 'published'),
  ('Endocrine', 'mcq', 'Which finding in a client with syndrome of inappropriate antidiuretic hormone secretion is expected?', '[{"id":"a","text":"Serum sodium 124 mEq/L"},{"id":"b","text":"Dilute urine"},{"id":"c","text":"Signs of dehydration"},{"id":"d","text":"Increased urine output"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'SIADH causes water retention and dilutional hyponatremia. Urine is concentrated and output is often low.', 'SIADH = too much water held in the body, so sodium becomes diluted.', 'Physiological Integrity', 'Analyze Cues', 'published'),
  ('Endocrine', 'mcq', 'A client after thyroidectomy reports tingling around the mouth and muscle cramps. Which complication does the nurse suspect?', '[{"id":"a","text":"Hypocalcemia"},{"id":"b","text":"Hyperglycemia"},{"id":"c","text":"Fluid overload"},{"id":"d","text":"Thyroid storm"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Parathyroid injury after thyroidectomy can cause hypocalcemia, producing tingling, cramps, tetany, or positive Chvostek/Trousseau signs.', 'After thyroid surgery, tingling and cramps point to low calcium from parathyroid disturbance.', 'Physiological Integrity', 'Recognize Cues', 'published'),
  ('Gastrointestinal', 'mcq', 'A client with cirrhosis becomes confused and has asterixis. Which lab value is most relevant?', '[{"id":"a","text":"Ammonia"},{"id":"b","text":"Troponin"},{"id":"c","text":"Creatine kinase"},{"id":"d","text":"Potassium"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Confusion and asterixis in cirrhosis suggest hepatic encephalopathy from elevated ammonia.', 'Liver failure plus mental status changes equals ammonia until proven otherwise.', 'Physiological Integrity', 'Analyze Cues', 'published'),
  ('Gastrointestinal', 'mcq', 'Which diet instruction is best for a client with dumping syndrome after gastric surgery?', '[{"id":"a","text":"Drink large amounts of fluid with meals"},{"id":"b","text":"Lie down after meals"},{"id":"c","text":"Eat high-sugar foods between meals"},{"id":"d","text":"Eat three large meals daily"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Lying down after meals can slow gastric emptying. Clients should eat small frequent meals, avoid high sugar, and limit fluids with meals.', 'Dumping syndrome = food moves too fast. Slow it with small meals, low sugar, and lying down after eating.', 'Physiological Integrity', 'Generate Solutions', 'published'),
  ('Gastrointestinal', 'mcq', 'A client with acute pancreatitis has severe epigastric pain radiating to the back. Which order should the nurse question?', '[{"id":"a","text":"NPO status"},{"id":"b","text":"IV opioid analgesic"},{"id":"c","text":"Low-fat solid meal tray"},{"id":"d","text":"IV fluids"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Oral intake stimulates pancreatic enzyme secretion and can worsen acute pancreatitis. NPO, fluids, and pain control are expected.', 'Pancreatitis care rests the pancreas: NPO, fluids, pain control.', 'Physiological Integrity', 'Evaluate Outcomes', 'published'),
  ('Neurological', 'mcq', 'A client has a sudden severe headache, vomiting, and decreased level of consciousness. Which condition is most concerning?', '[{"id":"a","text":"Migraine"},{"id":"b","text":"Subarachnoid hemorrhage"},{"id":"c","text":"Sinus infection"},{"id":"d","text":"Tension headache"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'A sudden severe headache with vomiting and decreased consciousness suggests hemorrhagic stroke/subarachnoid hemorrhage and requires emergency care.', 'Worst headache plus neuro decline is bleeding until proven otherwise.', 'Physiological Integrity', 'Prioritize Hypotheses', 'published'),
  ('Neurological', 'mcq', 'A client with myasthenia gravis has increasing difficulty swallowing and shallow respirations. What is the priority?', '[{"id":"a","text":"Offer a full meal"},{"id":"b","text":"Assess respiratory status and prepare for ventilatory support"},{"id":"c","text":"Encourage ambulation"},{"id":"d","text":"Delay medications until bedtime"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Myasthenic crisis can cause respiratory muscle weakness and airway compromise. Breathing is the priority.', 'Weakness disorders become emergencies when they affect swallowing or breathing.', 'Physiological Integrity', 'Take Action', 'published'),
  ('Neurological', 'mcq', 'Which action is appropriate for a client after a tonic-clonic seizure ends?', '[{"id":"a","text":"Place the client in a side-lying position"},{"id":"b","text":"Insert a padded tongue blade"},{"id":"c","text":"Restrain the arms"},{"id":"d","text":"Give oral fluids immediately"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'After a seizure, side-lying positioning helps maintain airway and allows secretions to drain. Nothing should be placed in the mouth.', 'Seizure care after: airway, side-lying, assess, document. Nothing in the mouth.', 'Safe and Effective Care Environment', 'Take Action', 'published'),
  ('Acid-Base Balance', 'mcq', 'A client has pH 7.50, PaCO2 30 mmHg, HCO3 24 mEq/L. How should the nurse interpret this?', '[{"id":"a","text":"Respiratory alkalosis"},{"id":"b","text":"Respiratory acidosis"},{"id":"c","text":"Metabolic acidosis"},{"id":"d","text":"Metabolic alkalosis"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'High pH indicates alkalosis. Low PaCO2 causes alkalosis by blowing off acid. HCO3 is normal, so this is respiratory alkalosis.', 'ROME: respiratory problems move opposite. pH high, CO2 low = respiratory alkalosis.', 'Physiological Integrity', 'Analyze Cues', 'published'),
  ('Acid-Base Balance', 'mcq', 'Which client is at highest risk for metabolic alkalosis?', '[{"id":"a","text":"Client with prolonged vomiting"},{"id":"b","text":"Client with diabetic ketoacidosis"},{"id":"c","text":"Client with renal failure and acidosis"},{"id":"d","text":"Client with severe diarrhea"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Vomiting causes loss of gastric acid, leading to metabolic alkalosis. DKA, renal failure, and diarrhea commonly cause metabolic acidosis.', 'Lose acid from the stomach, become alkalotic. Lose bicarbonate from diarrhea, become acidotic.', 'Physiological Integrity', 'Recognize Cues', 'published'),
  ('Acid-Base Balance', 'mcq', 'A client with anxiety is hyperventilating. Which ABG change is expected first?', '[{"id":"a","text":"PaCO2 decreases"},{"id":"b","text":"HCO3 increases immediately"},{"id":"c","text":"pH decreases"},{"id":"d","text":"Potassium rises sharply"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Hyperventilation blows off CO2, causing PaCO2 to fall and pH to rise. Renal compensation takes longer.', 'Breathing changes CO2 quickly. Kidneys change bicarbonate slowly.', 'Physiological Integrity', 'Analyze Cues', 'published'),
  ('Nutrition', 'mcq', 'Which meal choice is best for a client with iron-deficiency anemia?', '[{"id":"a","text":"Spinach salad with grilled chicken and orange slices"},{"id":"b","text":"White rice with tea"},{"id":"c","text":"Plain gelatin and cola"},{"id":"d","text":"Toast with coffee"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Iron-rich foods with vitamin C improve iron absorption. Tea and coffee can reduce absorption.', 'Pair iron with vitamin C. Avoid tea/coffee around iron.', 'Health Promotion and Maintenance', 'Generate Solutions', 'published'),
  ('Nutrition', 'mcq', 'A client receiving total parenteral nutrition suddenly has diaphoresis and tremors after the bag runs empty. What should the nurse suspect?', '[{"id":"a","text":"Rebound hypoglycemia"},{"id":"b","text":"Fluid overload"},{"id":"c","text":"Hypercalcemia"},{"id":"d","text":"Allergic reaction"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Abrupt discontinuation of TPN can cause rebound hypoglycemia because the client was receiving high glucose continuously.', 'Never stop TPN abruptly. If interrupted, hang dextrose per policy.', 'Physiological Integrity', 'Recognize Cues', 'published'),
  ('Nutrition', 'mcq', 'Which instruction is appropriate for a client with dysphagia?', '[{"id":"a","text":"Use thin liquids freely"},{"id":"b","text":"Sit upright during meals"},{"id":"c","text":"Tilt the head back to swallow"},{"id":"d","text":"Eat quickly before tiring"}]'::jsonb, '{"ids":["b"]}'::jsonb, 'Upright positioning reduces aspiration risk. Thickened liquids, slow pacing, and chin-tuck may be used depending on swallow evaluation.', 'Dysphagia safety = upright, slow, small bites, prescribed texture.', 'Safe and Effective Care Environment', 'Take Action', 'published'),
  ('Integumentary', 'mcq', 'Which pressure injury finding should the nurse stage as stage 2?', '[{"id":"a","text":"Intact purple area over the heel"},{"id":"b","text":"Full-thickness tissue loss with bone visible"},{"id":"c","text":"Partial-thickness skin loss with a shallow open blister"},{"id":"d","text":"Nonblanchable intact redness"}]'::jsonb, '{"ids":["c"]}'::jsonb, 'Stage 2 pressure injury involves partial-thickness skin loss, often appearing as a shallow open ulcer or blister.', 'Stage 1 intact red; Stage 2 partial skin loss/blister; Stage 4 bone/tendon.', 'Physiological Integrity', 'Analyze Cues', 'published'),
  ('Integumentary', 'mcq', 'A client has a new burn injury. Which assessment is the nurse''s priority?', '[{"id":"a","text":"Airway patency"},{"id":"b","text":"Body image concerns"},{"id":"c","text":"Long-term scar care"},{"id":"d","text":"Diet preferences"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Airway injury is the immediate life threat after burns, especially with facial burns, smoke exposure, or enclosed-space fire.', 'Burn priority: airway first, then fluids, then wound care.', 'Physiological Integrity', 'Prioritize Hypotheses', 'published'),
  ('Immune System', 'mcq', 'Which finding suggests anaphylaxis after antibiotic administration?', '[{"id":"a","text":"Wheezing and swelling of the lips"},{"id":"b","text":"Mild nausea only"},{"id":"c","text":"Dry mouth"},{"id":"d","text":"Temporary headache"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Wheezing and lip/tongue swelling indicate airway involvement and systemic allergic reaction requiring emergency treatment.', 'Allergy becomes anaphylaxis when airway, breathing, or circulation is involved.', 'Physiological Integrity', 'Recognize Cues', 'published'),
  ('Immune System', 'mcq', 'A client with HIV has a CD4 count of 180 cells/mm3. Which teaching is most important?', '[{"id":"a","text":"Report fever or new cough promptly"},{"id":"b","text":"Stop antiretroviral therapy when feeling better"},{"id":"c","text":"Avoid all exercise"},{"id":"d","text":"Share razors only with family"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'A CD4 count below 200 increases risk for opportunistic infections. Fever or respiratory symptoms need prompt evaluation.', 'CD4 under 200 = high infection risk. Infection symptoms matter fast.', 'Health Promotion and Maintenance', 'Take Action', 'published'),
  ('Eye and Ear', 'mcq', 'Which instruction is most important after cataract surgery?', '[{"id":"a","text":"Avoid bending at the waist"},{"id":"b","text":"Rub the eye if it itches"},{"id":"c","text":"Sleep on the operative side"},{"id":"d","text":"Lift heavy objects to resume activity"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Bending, rubbing, heavy lifting, and pressure on the operative eye can increase intraocular pressure and disrupt healing.', 'Eye surgery teaching: protect the eye and avoid pressure increases.', 'Safe and Effective Care Environment', 'Take Action', 'published'),
  ('Eye and Ear', 'mcq', 'A client reports sudden painless vision loss described as a curtain coming down. Which problem is suspected?', '[{"id":"a","text":"Retinal detachment"},{"id":"b","text":"Conjunctivitis"},{"id":"c","text":"Otitis media"},{"id":"d","text":"Cataract"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Retinal detachment may present with sudden painless vision loss, flashes, floaters, or a curtain-like shadow.', 'Curtain over vision = retina emergency.', 'Physiological Integrity', 'Recognize Cues', 'published'),
  ('Musculoskeletal', 'mcq', 'Which finding after total hip arthroplasty requires immediate action?', '[{"id":"a","text":"Leg internally rotated and shortened"},{"id":"b","text":"Pain rated 4/10 with movement"},{"id":"c","text":"Mild swelling near incision"},{"id":"d","text":"Use of abduction pillow"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Internal rotation and shortening suggest hip prosthesis dislocation. This requires immediate provider notification and immobilization.', 'After hip replacement, shortening plus rotation equals dislocation.', 'Physiological Integrity', 'Recognize Cues', 'published'),
  ('Musculoskeletal', 'mcq', 'A client with osteoporosis asks how to reduce fracture risk. Which instruction is best?', '[{"id":"a","text":"Perform weight-bearing exercise as tolerated"},{"id":"b","text":"Avoid calcium foods"},{"id":"c","text":"Stay in bed to prevent falls"},{"id":"d","text":"Take extra sedatives at night"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Weight-bearing exercise, calcium/vitamin D, fall prevention, and medication adherence reduce fracture risk.', 'Osteoporosis prevention is load the bones safely and prevent falls.', 'Health Promotion and Maintenance', 'Generate Solutions', 'published'),
  ('Medication Administration', 'mcq', 'Before administering an IV push opioid, which assessment is priority?', '[{"id":"a","text":"Respiratory rate"},{"id":"b","text":"Hair color"},{"id":"c","text":"Last bowel movement only"},{"id":"d","text":"Diet preference"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Opioids can depress respirations. Respiratory rate and sedation level must be assessed before administration.', 'Opioid safety: pain score matters, but breathing comes first.', 'Safe and Effective Care Environment', 'Recognize Cues', 'published'),
  ('Medication Administration', 'mcq', 'Which action follows the three checks of medication administration?', '[{"id":"a","text":"Check medication label against MAR when removing, preparing, and at bedside"},{"id":"b","text":"Check only after giving"},{"id":"c","text":"Ask another client to confirm"},{"id":"d","text":"Skip checks for familiar medications"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'The medication label is checked against the MAR when retrieving, preparing, and before administration to reduce errors.', 'Three checks are built to catch errors before the medication reaches the client.', 'Safe and Effective Care Environment', 'Take Action', 'published'),
  ('Perioperative Care', 'mcq', 'A postoperative client has stridor and restlessness after neck surgery. What is the priority action?', '[{"id":"a","text":"Assess airway and call for help"},{"id":"b","text":"Offer ice chips"},{"id":"c","text":"Encourage ambulation"},{"id":"d","text":"Place in Trendelenburg position"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Stridor indicates airway obstruction and is an emergency. Airway assessment and rapid help are priorities.', 'Stridor is airway narrowing. Treat it as an emergency every time.', 'Physiological Integrity', 'Prioritize Hypotheses', 'published'),
  ('Perioperative Care', 'mcq', 'Which instruction helps prevent postoperative atelectasis?', '[{"id":"a","text":"Use incentive spirometer regularly"},{"id":"b","text":"Avoid coughing completely"},{"id":"c","text":"Remain flat in bed"},{"id":"d","text":"Limit turning for 48 hours"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Incentive spirometry, coughing, deep breathing, turning, and early ambulation help re-expand alveoli and prevent atelectasis.', 'Post-op lungs need expansion: cough, deep breathe, incentive spirometer, move.', 'Physiological Integrity', 'Take Action', 'published'),
  ('Complex Care', 'mcq', 'A client with suspected sepsis has BP 84/48, temp 39.4 C, HR 128, and lactate 5.2. Which action is priority?', '[{"id":"a","text":"Begin ordered fluid resuscitation"},{"id":"b","text":"Delay antibiotics until fever resolves"},{"id":"c","text":"Place on a regular diet"},{"id":"d","text":"Limit vital signs to once daily"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Hypotension and elevated lactate indicate poor tissue perfusion in sepsis. Fluid resuscitation and rapid sepsis protocol care are priorities.', 'Sepsis priority is perfusion: fluids, cultures/antibiotics per protocol, lactate trends.', 'Physiological Integrity', 'Take Action', 'published'),
  ('Complex Care', 'mcq', 'Which client should the emergency nurse see first?', '[{"id":"a","text":"Client with chest pain and diaphoresis"},{"id":"b","text":"Client with ankle sprain and swelling"},{"id":"c","text":"Client requesting a work note"},{"id":"d","text":"Client with mild sore throat for 3 days"}]'::jsonb, '{"ids":["a"]}'::jsonb, 'Chest pain with diaphoresis suggests possible acute coronary syndrome and takes priority over stable, non-life-threatening concerns.', 'Triage asks: who may die soon? Chest pain plus diaphoresis wins.', 'Safe and Effective Care Environment', 'Prioritize Hypotheses', 'published')
) as seed(topic, question_type, prompt, choices, correct_answer, rationale, strategy, client_need, clinical_judgment, status)
where not exists (
  select 1
  from public.questions q
  where q.prompt = seed.prompt
);
